    -- Speaker names and spoken lines for dialog-triggered route steps
    ["Amirdrassil will be defended"] = "Mit der Macht des Samenkorns können wir Amirdrassil verteidigen. Fyrakk wird scheitern.",
    ["barrier has fallen"] = "Die Barriere bricht zusammen! Lasst uns sehen, wie mutig Aschenwind ohne ihren magischen Schutzschild ist.",
    ["Brann Bronzebeard"] = "Brann Bronzebart",
    ["chaos in the city streets"] = "Ihr seid noch am Leben! Gut. Es herrscht Chaos in der Stadt.",
    ["decontamination chamber"] = "Virulentes Exemplar vernichtet. Öffne Dekontaminierungskammer.",
    ["find the last font"] = "Gut gemacht! Nun bleibt nur noch eine Quelle, die wir zerstören müssen.",
    ["First Arcanist Thalyssra"] = "Erste Arkanistin Thalyssra",
    ["get these doors open"] = "Eine Sekunde. Ich hab die Tür so gut wie auf.",
    ["Image of Aegwynn"] = "Abbild von Aegwynn",
    ["It is finished then"] = "Es ist also vollbracht!",
    ["Lorewalker Cho"] = "Lehrensucher Cho",
    ["lust for power"] = "Garrosh verbirgt hier 'nen ganzen Stützpunkt. Wozu hat die Gier nach Macht ihn getrieben?",
    ["Malfurion Stormrage"] = "Malfurion Sturmgrimm",
    ["Merithra"] = "Merithra",
    ["purify your hearts"] = "Diese Tränen von vollendeter Schönheit verkörpern den Traum von unserer Welt, wie sie sein könnte. Heute läutern sie Eure Herzen für die kommende Schlacht.",
    ["Seed of Life, we are one step closer"] = "Mit diesem Samenkorn sind wir Fyrakks Ende einen Schritt näher.",
    ["shatters the bonds of fate"] = "Dieser Hammer hat uralte Wunder geschmiedet sowie die Erde selbst geformt. Heute zerschmettert er die Bande des Schicksals, die uns alle vernichten wollen.",
    ["Tyrande Whisperwind"] = "Tyrande Wisperwind",
    ["Vol'jin"] = "Vol'jin",
    ["Warlord Zaela"] = "Kriegsfürstin Zaela",
    ["washes clean the darkness"] = "Diesem Stein entsprangen einst Flüsse und Ozeane – die Lebensessenz von Azeroth. Heute spült er die Dunkelheit fort, die unsere Welt umklammert.",
    ["What might this button do"] = "Ah, die uralten Gewölbe der Könige von Mogu'shan. Wofür wohl dieser Schalter da ist?",
    ["Your blood will fill this bay"] = "Ihr glaubt, Ihr habt gewonnen? Wir sind Orcs! Reinen Blutes und unter dem Befehl des größten Kriegshäuptlings aller Zeiten! Euer Blut wird diese Bucht füllen!",

