    ["Ephemeral Plains Alpha"] = "Ephemere Ebenen Alpha",
    ["Galewind Crag"] = "Sturmböenklippe",
    ["Genesis Cradle Alpha"] = "Wiege der Genesis Alpha",
    ["Lightforged Beacon"] = "Lichtgeschmiedetes Signal",
    ["Lightforged Warframes"] = "Lichtgeschmiedete Kriegspanzerungen",
    ["Orb of Culmination"] = "Kugel der Vollendung",
    ["Shanna Sparkfizz"] = "Shanna Funkenzisch",
    ["The Traverse"] = "Der Übergang",

    -- Login banner and idle-panel prompt
    ["Type |cffffffff/rr|r to load navigation."] = "Gebt |cffffffff/rr|r ein, um die Navigation zu laden.",
    ["|cffaaaaaav%s loaded. Type |r|cffffffff/rr help|r|cffaaaaaa for commands.|r"] = "|cffaaaaaav%s geladen. Gebt |r|cffffffff/rr help|r|cffaaaaaa für Befehle ein.|r",

    -- Route content translations
    ["/reload if stuck"] = "/reload bei Problemen",
    ["1"] = "1",
    ["1. When he's threatening to roll left, strafe right (and vice versa). You get 8-10 seconds after he emotes. 2. Stand by the front (armor plate), pulling enemies to you and killing them near the armor plate. 3. Kill ^Hideous Amalgamation^ on the armor to pry up the armor plates. 4. Prying up an armor plate exposes a ^Burning Tendon^. Kill it to advance. Doing this 3x will end the fight."] = "1. Wenn er ankündigt, nach links zu rollen, weicht nach rechts aus und umgekehrt. Nach seiner Emote-Nachricht habt Ihr 8–10 Sekunden. 2. Steht vorne an der Panzerplatte, zieht Gegner zu euch und tötet sie dort. 3. Tötet ^Hideous Amalgamation^ auf der Panzerung, um die Panzerplatten anzuheben. 4. Eine angehobene Panzerplatte legt eine ^Burning Tendon^ frei. Tötet sie, um voranzukommen. Nach 3 Wiederholungen endet der Kampf.",
    ["2"] = "2",
    ["3"] = "3",
    ["^Immerseus^ alternates between phases several times. Phase1: Hit the boss. Phase2: Kill black blobs, heal blue ones if you can. The more killing/healing, the faster the fight."] = "^Immerseus^ wechselt mehrmals zwischen zwei Phasen. Phase 1: Greift den Boss an. Phase 2: Tötet schwarze Blasen und heilt nach Möglichkeit die blauen. Je mehr Ihr tötet und heilt, desto schneller endet der Kampf.",
    ["^Mythic^-- Just nuke the boss. ^Heroic^/^Normal^: Kill trash to fill the energy bar. Eventually, (3) ^Unstable Core^ will drop. Pick them up and carry each of them towards the boss, and use the Extra Action Button to throw them. After doing this 3 times, the boss will spawn."] = "^Mythic^ – Greift den Boss einfach mit voller Kraft an. ^Heroic^/^Normal^: Tötet Gegner, um die Energieleiste zu füllen. Schließlich fallen (3) ^Unstable Core^ zu Boden. Hebt sie auf, tragt sie nacheinander zum Boss und werft sie mit der Extraaktionsschaltfläche. Nach 3 Wiederholungen erscheint der Boss.",
    ["Action Button in Beam"] = "Aktionsbutton im Strahl",
    ["After a brief dialog, kill ^Raszageth the Storm-Eater^!"] = "Tötet nach einem kurzen Dialog ^Raszageth the Storm-Eater^!",
    ["After activating the ^Titan Console^, kill several waves of adds from the previous room to unlock the door to the next room."] = "Nachdem Ihr die ^Titan Console^ aktiviert habt, tötet mehrere Wellen zusätzlicher Gegner aus dem vorherigen Raum, um die Tür zum nächsten Raum zu öffnen.",
    ["After arriving at ^The Torment Chambers^, follow the path to ^Soulrender Dormazain^."] = "Nachdem Ihr ^The Torment Chambers^ erreicht habt, folgt dem Weg zu ^Soulrender Dormazain^.",
    ["After arriving back in ^Halls of the Faithful^, follow the path all the way around to ^Artificer Xy'mox^. Kill the trash, and ^Prince Renathal^ will show up to open the gate."] = "Nachdem Ihr wieder in ^Halls of the Faithful^ angekommen seid, folgt dem Weg vollständig um den Bereich herum zu ^Artificer Xy'mox^. Tötet die Trashgegner, dann erscheint ^Prince Renathal^ und öffnet das Tor.",
    ["After arriving back in ^The Grand Walk^, follow the path up to where you killed ^Shriekwing^. This time, take the path right/south to end up in ^Halls of the Faithful^."] = "Nachdem Ihr wieder in ^The Grand Walk^ angekommen seid, folgt dem Weg hinauf zu der Stelle, an der Ihr ^Shriekwing^ getötet habt. Nehmt diesmal den rechten beziehungsweise südlichen Weg, um ^Halls of the Faithful^ zu erreichen.",
    ["After arriving back in Antorus, follow the path to the left to reach ^Portal Keeper Hasabel^."] = "Nachdem Ihr wieder in Antorus angekommen seid, folgt dem linken Weg zu ^Portal Keeper Hasabel^.",
    ["After arriving back in the ^Ring of Containment^, head straight ahead towards the map exit labeled ^The Oblivion Door^."] = "Nachdem Ihr wieder im ^Ring of Containment^ angekommen seid, geht geradeaus zum Kartenausgang mit der Bezeichnung ^The Oblivion Door^.",
    ["After arriving back on the ^Wyrmrest Summit^, talk to ^Kalecgos^ to advance."] = "Nachdem Ihr wieder auf dem ^Wyrmrest Summit^ angekommen seid, sprecht mit ^Kalecgos^, um fortzufahren.",
    ["After arriving in ^Crown of Gorgoa^, follow the path North to ^Guardian of the First Ones^."] = "Nachdem Ihr ^Crown of Gorgoa^ erreicht habt, folgt dem Weg nach Norden zu ^Guardian of the First Ones^.",
    ["After arriving in ^The Burning Throne^, proceed down the long path and kill ^Tarneth^ to open the door. Continue west to the map exit labeled ^The World Soul^."] = "Nachdem Ihr ^The Burning Throne^ erreicht habt, folgt dem langen Weg und tötet ^Tarneth^, um die Tür zu öffnen. Geht weiter nach Westen zum Kartenausgang mit der Bezeichnung ^The World Soul^.",
    ["After arriving in ^The Burning Throne^, proceed down the path and kill ^Tarneth^ to open the door. Jump in the hole behind the next trash pack."] = "Nachdem Ihr ^The Burning Throne^ erreicht habt, folgt dem Weg und tötet ^Tarneth^, um die Tür zu öffnen. Springt in das Loch hinter der nächsten Trashgruppe.",
    ["After arriving in ^The Emerald Nightmare^, proceed forward to start the encounter with ^Dragons of Nightmare^."] = "Nachdem Ihr ^The Emerald Nightmare^ erreicht habt, geht vorwärts, um die Begegnung mit ^Dragons of Nightmare^ zu beginnen.",
    ["After arriving in ^The Oblivion Door^, clear all trash to start the encounter with ^Zul, Reborn^."] = "Nachdem Ihr ^The Oblivion Door^ erreicht habt, tötet alle Trashgegner, um die Begegnung mit ^Zul, Reborn^ zu beginnen.",
    ["After arriving in ^The Twisting Nether^, work your way down the path, killing trash all the way until you reach ^Kil'Jaeden^."] = "Nachdem Ihr ^The Twisting Nether^ erreicht habt, arbeitet euch den Weg hinab und tötet alle Trashgegner, bis Ihr ^Kil'Jaeden^ erreicht.",
    ["After arriving in the room with ^Lady Inerva Darkvein^, kill all the trash to trigger some dialog, then kill the boss."] = "Nachdem Ihr den Raum mit ^Lady Inerva Darkvein^ erreicht habt, tötet alle Trashgegner, um einen Dialog auszulösen, und tötet anschließend den Boss.",
    ["After arriving on ^Wyrmrest Summit^, talk to ^Kalecgos^ to advance."] = "Nachdem Ihr ^Wyrmrest Summit^ erreicht habt, sprecht mit ^Kalecgos^, um fortzufahren.",
    ["After back in the ^Ring of Containment^, head to the leftmost map exit labeled ^Archives of Eternity^."] = "Nachdem Ihr wieder im ^Ring of Containment^ seid, geht zum äußersten linken Kartenausgang mit der Bezeichnung ^Archives of Eternity^.",
    ["After clearing the final trash wave, follow the path up to engage ^The Spirit Kings^."] = "Nachdem Ihr die letzte Trashwelle besiegt habt, folgt dem Weg hinauf und greift ^The Spirit Kings^ an.",
    ["After clicking the ^Hammer^, proceed down the stairs towards the west side of the room and the map exit labeled ^The Abyssal Throne^."] = "Nachdem Ihr auf den ^Hammer^ geklickt habt, geht die Treppe zur Westseite des Raums hinab und zum Kartenausgang mit der Bezeichnung ^The Abyssal Throne^.",
    ["After clicking the ^Tears of Elune^, jump off the edge to die and respawn back in ^Chamber of the Moon^."] = "Nachdem Ihr auf die ^Tears of Elune^ geklickt habt, springt vom Rand, um zu sterben und wieder in ^Chamber of the Moon^ zu erscheinen.",
    ["After clicking the ^Tidestone^, backtrack a bit and take a right towards the map exit labeled ^Terrace of the Moon^. You will pass a giant statue and begin climbing a long, winding staircase."] = "Nachdem Ihr auf den ^Tidestone^ geklickt habt, geht ein Stück zurück und biegt rechts zum Kartenausgang mit der Bezeichnung ^Terrace of the Moon^ ab. Ihr kommt an einer riesigen Statue vorbei und steigt eine lange, gewundene Treppe hinauf.",
    ["After clicking the first orb, follow the path all the way north to kill ^Radiance of Azshara^. Clear all the trash to start the encounter."] = "Nachdem Ihr auf die erste Kugel geklickt habt, folgt dem Weg ganz nach Norden und tötet ^Radiance of Azshara^. Tötet alle Trashgegner, um die Begegnung zu beginnen.",
    ["After clicking the lever, travel through the opened door to the northeast and follow it around to a big clearing. Take the southwestern door."] = "Nachdem Ihr auf den Hebel geklickt habt, geht durch die geöffnete Tür im Nordosten und folgt dem Weg bis zu einer großen Lichtung. Nehmt die südwestliche Tür.",
    ["After clicking the orb, the path opens to fight ^Lady Ashvane^."] = "Nachdem Ihr die Kugel angeklickt habt, öffnet sich der Weg zum Kampf gegen ^Lady Ashvane^.",
    ["After coming out of the water, take the path south towards the map exit labeled ^Darkest Depths^."] = "Nachdem Ihr aus dem Wasser gekommen seid, folgt dem Weg nach Süden zum Kartenausgang mit der Bezeichnung ^Darkest Depths^.",
    ["After completing the ^Hellfire Assault^ encounter, you will find ^Iron Reaver^ spawned right in front of you."] = "Nachdem Ihr die Begegnung ^Hellfire Assault^ abgeschlossen habt, findet Ihr ^Iron Reaver^ direkt vor euch.",
    ["After completing the ^Norushen^ encounter, move ahead into the next room and clear all trash to start the fight with ^Sha of Pride^."] = "Nachdem Ihr die Begegnung ^Norushen^ abgeschlossen habt, geht in den nächsten Raum und beseitigt alle Gegner, um den Kampf gegen ^Sha of Pride^ zu beginnen.",
    ["After completing the ^Spoils of Pandaria^ encounter, follow the path ahead to reach ^Thok the Bloodthirsty^."] = "Nachdem Ihr die Begegnung ^Spoils of Pandaria^ abgeschlossen habt, folgt dem Weg vor euch zu ^Thok the Bloodthirsty^.",
    ["After defeating ^Aggramar^, speak to ^Magni Bronzebeard^ and tell him you're ready."] = "Nachdem Ihr ^Aggramar^ besiegt habt, sprecht mit ^Magni Bronzebeard^ und sagt ihm, dass Ihr bereit seid.",
    ["After defeating ^Aluriel^, take the path into the building to the northeast, and clear trash as you approach the map exit labeled ^Astromancer's Rise^."] = "Nachdem Ihr ^Aluriel^ besiegt habt, folgt dem Weg in das Gebäude im Nordosten und beseitigt auf dem Weg zum Kartenausgang mit der Bezeichnung ^Astromancer's Rise^ alle Gegner.",
    ["After defeating ^Alysrazor^, you will find ^Shannox^ patrolling around the main circular path of the instance. If he hasn't spawned yet, kill random trash until he emotes."] = "Nachdem Ihr ^Alysrazor^ besiegt habt, findet Ihr ^Shannox^ auf der großen kreisförmigen Route durch die Instanz patrouillierend. Falls er noch nicht erschienen ist, tötet beliebige Gegner, bis er eine Emote-Nachricht ausgibt.",
    ["After defeating ^Amber-Shaper Un'sok^, exit the room to the west and head straight for ^Grand Empress Shek'zeer^. Clear all the trash to spawn the boss."] = "Nachdem Ihr ^Amber-Shaper Un'sok^ besiegt habt, verlasst den Raum nach Westen und geht direkt zu ^Grand Empress Shek'zeer^. Beseitigt alle Gegner, damit der Boss erscheint.",
    ["After defeating ^Argaloth^, head to the north wing to face ^Alizabal^."] = "Nachdem Ihr ^Argaloth^ besiegt habt, begebt euch in den nördlichen Flügel, um gegen ^Alizabal^ anzutreten.",
    ["After defeating ^Artificer Xy'mox^, backtrack out of the room and follow the path to the stairs leading to ^Feast of Arrogance^."] = "Nachdem Ihr ^Artificer Xy'mox^ besiegt habt, geht aus dem Raum zurück und folgt dem Weg zu den Treppen, die nach ^Feast of Arrogance^ führen.",
    ["After defeating ^Beth'tilac^, follow the path all the way to the southeastern corner of the map to reach ^Lord Rhyolith^. Kill trash on your path, to minimize the amount you have to kill later to spawn ^Shannox^."] = "Nachdem Ihr ^Beth'tilac^ besiegt habt, folgt dem Weg bis in die südöstliche Ecke der Karte zu ^Lord Rhyolith^. Tötet unterwegs Gegner, damit Ihr später weniger beseitigen müsst, um ^Shannox^ erscheinen zu lassen.",
    ["After defeating ^Brackenspore^, go back out the way you came and travel far west to reach a portal."] = "Nachdem Ihr ^Brackenspore^ besiegt habt, geht auf demselben Weg zurück und weit nach Westen zu einem Portal.",
    ["After defeating ^Champion of the Light^, continue down the path, clearing trash on the way to ^Grong^."] = "Nachdem Ihr ^Champion of the Light^ besiegt habt, folgt dem Weg weiter und beseitigt unterwegs die Gegner bis zu ^Grong^.",
    ["After defeating ^Chimaeron^, go back out to the main ring and follow the path to the ^Orb of Culmination^. Interact with it to begin the encounter with ^Nefarian^."] = "Nachdem Ihr ^Chimaeron^ besiegt habt, kehrt zum Hauptring zurück und folgt dem Weg zur ^Orb of Culmination^. Interagiert damit, um die Begegnung mit ^Nefarian^ zu beginnen.",
    ["After defeating ^Cho'gall^, jump in the hole in the middle of the room."] = "Nachdem Ihr ^Cho'gall^ besiegt habt, springt in das Loch in der Mitte des Raums.",
    ["After defeating ^Conclave of the Chosen^, exit the room to the east, and take the elevator up."] = "Nachdem Ihr ^Conclave of the Chosen^ besiegt habt, verlasst den Raum nach Osten und fahrt mit dem Aufzug nach oben.",
    ["After defeating ^Conclave of Wind^, collect the loot chest on the north platform, then click on the nearby ^Slipstream^ to be flown to the main platform to face ^Al'Akir^."] = "Nachdem Ihr ^Conclave of Wind^ besiegt habt, plündert die Truhe auf der nördlichen Plattform und klickt dann auf den nahe gelegenen ^Slipstream^, um zur Hauptplattform und zu ^Al'Akir^ geflogen zu werden.",
    ["After defeating ^Conclave^, exit the room to the east and ride the elevator up to the ^Walk of Kings^."] = "Nachdem Ihr ^Conclave^ besiegt habt, verlasst den Raum nach Osten und fahrt mit dem Aufzug hinauf zu ^Walk of Kings^.",
    ["After defeating ^Council of Elders^, go through the door behind them. As you cross the bridge, there will be a cutscene and you will fall below."] = "Nachdem Ihr ^Council of Elders^ besiegt habt, geht durch die Tür hinter ihnen. Beim Überqueren der Brücke folgt eine Zwischensequenz, und Ihr fallt nach unten.",
    ["After defeating ^Dark Animus^, take the northern stairwell out of the room and follow the path to open a masked gate."] = "Nachdem Ihr ^Dark Animus^ besiegt habt, nehmt das nördliche Treppenhaus aus dem Raum und folgt dem Weg, um ein versiegeltes Tor zu öffnen.",
    ["After defeating ^Durumu^, follow the linear path through several sets of stairs and make your way to ^Primordius^."] = "Nachdem Ihr ^Durumu^ besiegt habt, folgt dem geradlinigen Weg über mehrere Treppen bis zu ^Primordius^.",
    ["After defeating ^Echo of Neltharion^, walk into the room behind him and jump into the purple circle to reach ^Edge of Oblivion^."] = "Nachdem Ihr ^Echo of Neltharion^ besiegt habt, geht in den Raum hinter ihm und springt in den violetten Kreis, um ^Edge of Oblivion^ zu erreichen.",
    ["After defeating ^Elerethe^, backtrack to the portal and return to ^Core of the Nightmare^. You can jump off the ledge for a shortcut."] = "Nachdem Ihr ^Elerethe^ besiegt habt, kehrt zum Portal zurück und reist nach ^Core of the Nightmare^. Für eine Abkürzung könnt Ihr vom Vorsprung springen.",
    ["After defeating ^Elisande^, approach the teleporter outside the room and choose ^Font of Night^ as your destination."] = "Nachdem Ihr ^Elisande^ besiegt habt, geht zum Teleporter außerhalb des Raums und wählt ^Font of Night^ als Ziel.",
    ["After defeating ^Fel Lord Zakuun^, climb out of this area the way you came, and go all the way east to reach ^Xhul'horac^. Kill trash to start the encounter."] = "Nachdem Ihr ^Fel Lord Zakuun^ besiegt habt, verlasst diesen Bereich auf demselben Weg und geht ganz nach Osten zu ^Xhul'horac^. Tötet die Gegner, um die Begegnung zu beginnen.",
    ["After defeating ^Felhounds of Sargeras^, backtrack towards the closest intersection and keep to the left. Kill a trash pack to spawn a ^Lightforged Teleportation Pad^. Use it to cross the chasm, then proceed ahead to ride an elevator up."] = "Nachdem Ihr ^Felhounds of Sargeras^ besiegt habt, kehrt zur nächsten Kreuzung zurück und haltet euch links. Tötet eine Gegnergruppe, damit ein ^Lightforged Teleportation Pad^ erscheint. Benutzt es, um die Schlucht zu überqueren, und fahrt anschließend mit dem Aufzug nach oben.",
    ["After defeating ^Flamebender Ka'graz^, head slightly east and then follow the path north to reach ^Kromog^."] = "Nachdem Ihr ^Flamebender Ka'graz^ besiegt habt, geht ein Stück nach Osten und folgt dann dem Weg nach Norden zu ^Kromog^.",
    ["After defeating ^Garothi Worldbreaker^, continue straight ahead on the path to ^Felhounds of Sargeras^."] = "Nachdem Ihr ^Garothi Worldbreaker^ besiegt habt, folgt dem Weg geradeaus zu ^Felhounds of Sargeras^.",
    ["After defeating ^Garothi Worldbreaker^, cross the bridge and take a left to locate a teleporter. Select ^The Burning Throne^ to skip ahead to ^Aggramar^."] = "Nachdem Ihr ^Garothi Worldbreaker^ besiegt habt, überquert die Brücke und biegt links ab, um einen Teleporter zu finden. Wählt ^The Burning Throne^, um direkt zu ^Aggramar^ zu gelangen.",
    ["After defeating ^General Nazgrim^, take the elevator down in the northeastern section of the room."] = "Nachdem Ihr ^General Nazgrim^ besiegt habt, fahrt mit dem Aufzug im nordöstlichen Bereich des Raums nach unten.",
    ["After defeating ^Goroth^, proceed straight ahead past the group of NPCs and go up the stairs to find ^Demonic Inquisition^."] = "Nachdem Ihr ^Goroth^ besiegt habt, geht geradeaus an der NPC-Gruppe vorbei und die Treppe hinauf zu ^Demonic Inquisition^.",
    ["After defeating ^Grong^, follow the winding path around to ^Jadefire Masters^. Kill the trash to start the encounter."] = "Nachdem Ihr ^Grong^ besiegt habt, folgt dem gewundenen Weg zu ^Jadefire Masters^. Tötet die Gegner, um die Begegnung zu beginnen.",
    ["After defeating ^Hagara^, click the ^portal^ to return to ^Wyrmrest Summit^."] = "Nachdem Ihr ^Hagara^ besiegt habt, klickt auf das ^portal^, um nach ^Wyrmrest Summit^ zurückzukehren.",
    ["After defeating ^Halfus^, follow the path straight south to reach ^Theralion and Valiona^. Kill trash to begin the gauntlet on the way to the boss."] = "Nachdem Ihr ^Halfus^ besiegt habt, folgt dem Weg gerade nach Süden zu ^Theralion and Valiona^. Tötet die Gegner, um den Spießrutenlauf auf dem Weg zum Boss zu beginnen.",
    ["After defeating ^High Botanist Tel'arn^, backtrack towards the map exit labeled ^The Nighthold^."] = "Nachdem Ihr ^High Botanist Tel'arn^ besiegt habt, kehrt zum Kartenausgang mit der Bezeichnung ^The Nighthold^ zurück.",
    ["After defeating ^Il'gynoth^, interact with the nearby ^Re-origination Anchor^ to be flown back to the top."] = "Nachdem Ihr ^Il'gynoth^ besiegt habt, interagiert mit dem nahe gelegenen ^Re-origination Anchor^, um wieder nach oben geflogen zu werden.",
    ["After defeating ^Immerseus^, take the tall western stairwell behind him."] = "Nachdem Ihr ^Immerseus^ besiegt habt, nehmt das hohe westliche Treppenhaus hinter ihm.",
    ["After defeating ^Iron Maidens^, take the southern path and keep to the left until you reach ^Hans'gar and Franzok^. After a brief dialog, kill the trash to start the encounter."] = "Nachdem Ihr ^Iron Maidens^ besiegt habt, nehmt den südlichen Weg und haltet euch links, bis Ihr ^Hans'gar and Franzok^ erreicht. Tötet nach einem kurzen Dialog die Gegner, um die Begegnung zu beginnen.",
    ["After defeating ^Iron Qon^, proceed through the new door behind them and follow the linear path to the ^Twin Empyreans^."] = "Nachdem Ihr ^Iron Qon^ besiegt habt, geht durch die neue Tür hinter ihnen und folgt dem geradlinigen Weg zu ^Twin Empyreans^.",
    ["After defeating ^Jadefire Masters^, go up the stairs behind them toward the map exit labeled ^The Heart of the Empire^. Open the door to continue."] = "Nachdem Ihr ^Jadefire Masters^ besiegt habt, geht die Treppe hinter ihnen hinauf zum Kartenausgang mit der Bezeichnung ^The Heart of the Empire^. Öffnet die Tür, um weiterzugehen.",
    ["After defeating ^Jadefire Masters^, proceed up the long staircase behind them to reach ^Grong, the Revenant^. Kill trash at the top of the stairs to start the encounter."] = "Nachdem Ihr ^Jadefire Masters^ besiegt habt, geht die lange Treppe hinter ihnen hinauf zu ^Grong, the Revenant^. Tötet oben die Gegner, um die Begegnung zu beginnen.",
    ["After defeating ^Kazzara^, click the vent behind ^Neltharion^ and you will be able to jump down and skip ahead to the ^Echo of Neltharion^ encounter."] = "Nachdem Ihr ^Kazzara^ besiegt habt, klickt auf den Abzug hinter ^Neltharion^. So könnt Ihr hinunterspringen und die Begegnung mit ^Echo of Neltharion^ als Abkürzung erreichen.",
    ["After defeating ^King Rastakhan^, take the western exit from the room and make your way towards the map exit labeled ^Port of Zandalar^. Interact with the ^7th Legion Gryphon^ to be flown to the next area."] = "Nachdem Ihr ^King Rastakhan^ besiegt habt, verlasst den Raum nach Westen und begebt euch zum Kartenausgang mit der Bezeichnung ^Port of Zandalar^. Interagiert mit dem ^7th Legion Gryphon^, um in den nächsten Bereich geflogen zu werden.",
    ["After defeating ^King Rastakhan^, take the western exit from the room and make your way towards the map exit labeled ^Port of Zandalar^. Interact with the ^Riding Pterrordax^ to be flown to the next area."] = "Nachdem Ihr ^King Rastakhan^ besiegt habt, verlasst den Raum nach Westen und begebt euch zum Kartenausgang mit der Bezeichnung ^Port of Zandalar^. Interagiert mit dem ^Riding Pterrordax^, um in den nächsten Bereich geflogen zu werden.",
    ["After defeating ^Krosus^, backtrack up to the main courtyard and click the portal to teleport to ^The Nightspire^. After landing, proceed ahead into the boss room."] = "Nachdem Ihr ^Krosus^ besiegt habt, kehrt zum Haupthof zurück und klickt auf das Portal nach ^The Nightspire^. Geht nach der Landung weiter in den Bossraum.",
    ["After defeating ^Lei Shi^, continue straight up the stairs to engage ^Sha of Fear^."] = "Nachdem Ihr ^Lei Shi^ besiegt habt, geht geradeaus die Treppe hinauf und greift ^Sha of Fear^ an.",
    ["After defeating ^Magmorax^, swim across the lava to reach the southern exit labeled ^Neltharion's Sanctum^. Jump down into the hole."] = "Nachdem Ihr ^Magmorax^ besiegt habt, schwimmt durch die Lava zum südlichen Ausgang mit der Bezeichnung ^Neltharion's Sanctum^. Springt in das Loch hinab.",
    ["After defeating ^Maloriak^, exit back to the main ring and head to the north exit. Kill trash, then hit the large bell at the back of the room to begin the encounter with ^Atramedes^."] = "Nachdem Ihr ^Maloriak^ besiegt habt, kehrt zum Hauptring zurück und nehmt den nördlichen Ausgang. Tötet die Gegner und schlagt dann die große Glocke hinten im Raum, um die Begegnung mit ^Atramedes^ zu beginnen.",
    ["After defeating ^Megaera^, take the new exit on the east side of the room."] = "Nachdem Ihr ^Megaera^ besiegt habt, nehmt den neuen Ausgang auf der Ostseite des Raums.",
    ["After defeating ^Mekkatorque^, make your way down the long path south, and kill the trash at the end of the bridge. Interact with a ^Pterrordax^ to start the encounter with ^Stormwall Blockade^."] = "Nachdem Ihr ^Mekkatorque^ besiegt habt, folgt dem langen Weg nach Süden und tötet die Gegner am Ende der Brücke. Interagiert mit einem ^Pterrordax^, um die Begegnung mit ^Stormwall Blockade^ zu beginnen.",
    ["After defeating ^Morchok^, continue ahead into ^Wyrmrest Temple^. Interact with ^Valeera^, the dragon on the left."] = "Nachdem Ihr ^Morchok^ besiegt habt, geht weiter in den ^Wyrmrest Temple^. Interagiert mit ^Valeera^, dem Drachen auf der linken Seite.",
    ["After defeating ^MOTHER^, continue forward to the map exit labeled ^Ring of Containment^."] = "Nachdem Ihr ^MOTHER^ besiegt habt, geht weiter zum Kartenausgang mit der Bezeichnung ^Ring of Containment^.",
    ["After defeating ^Mythrax^, follow the path north to engage the final boss, ^G'huun^."] = "Nachdem Ihr ^Mythrax^ besiegt habt, folgt dem Weg nach Norden zum letzten Boss, ^G'huun^.",
    ["After defeating ^Nythendra^, follow the path up and around towards the map exit labeled ^Core of the Nightmare^."] = "Nachdem Ihr ^Nythendra^ besiegt habt, folgt dem Weg hinauf und herum zum Kartenausgang mit der Bezeichnung ^Core of the Nightmare^.",
    ["After defeating ^Odyn^, talk to him and select the only dialog option available. You will be dropped into ^Helheim^."] = "Nachdem Ihr ^Odyn^ besiegt habt, sprecht mit ihm und wählt die einzige verfügbare Dialogoption. Ihr werdet nach ^Helheim^ hinabgelassen.",
    ["After defeating ^Operator Thogar^, jump down the hole marked on the east side of the room."] = "Nachdem Ihr ^Operator Thogar^ besiegt habt, springt durch das markierte Loch auf der Ostseite des Raums.",
    ["After defeating ^Portal Keeper Hasabel^, leave the boss room and stay to the right to find the map exit labeled ^Elunaria^. Click the portal."] = "Nachdem Ihr ^Portal Keeper Hasabel^ besiegt habt, verlasst den Bossraum und haltet euch rechts, bis Ihr den Kartenausgang mit der Bezeichnung ^Elunaria^ findet. Klickt auf das Portal.",
    ["After defeating ^Protectors of the Endless^, there will be a brief delay and then ^Tsulong^ will spawn at the same location."] = "Nachdem Ihr ^Protectors of the Endless^ besiegt habt, erscheint ^Tsulong^ nach einer kurzen Verzögerung an derselben Stelle.",
    ["After defeating ^Ra-den^, interact with the ^Re-origination Anchor^ right behind him to be flown back below."] = "Nachdem Ihr ^Ra-den^ besiegt habt, interagiert direkt hinter ihm mit dem ^Re-origination Anchor^, um wieder nach unten geflogen zu werden.",
    ["After defeating ^Radiance of Azshara^, leave the room the way you came and find 2 more ^Azsh'ari Channelers^ guarding an orb. Kill them and click ^Font of Power^."] = "Nachdem Ihr ^Radiance of Azshara^ besiegt habt, verlasst den Raum auf demselben Weg und sucht 2 weitere ^Azsh'ari Channelers^, die eine Kugel bewachen. Tötet sie und klickt auf ^Font of Power^.",
    ["After defeating ^Rashok^, make your way up the chain behind him, and follow the path around to ^The Vigilant Steward, Zskarn^."] = "Nachdem Ihr ^Rashok^ besiegt habt, klettert die Kette hinter ihm hinauf und folgt dem Weg zu ^The Vigilant Steward, Zskarn^.",
    ["After defeating ^Sha of Pride^, watch some dialog then click the portal in the southwest corner of the room."] = "Nachdem Ihr ^Sha of Pride^ besiegt habt, wartet den Dialog ab und klickt dann auf das Portal in der südwestlichen Ecke des Raums.",
    ["After defeating ^Shad'har^, leave his room and continue down the spiral."] = "Nachdem Ihr ^Shad'har^ besiegt habt, verlasst seinen Raum und folgt der Spirale weiter nach unten.",
    ["After defeating ^Shannox^, head north to reach ^Baleroc^."] = "Nachdem Ihr ^Shannox^ besiegt habt, geht nach Norden zu ^Baleroc^.",
    ["After defeating ^Siegecrafter Blackfuse^, jump back in the pipe towards the room entrance. Continue southwest back the way you came."] = "Nachdem Ihr ^Siegecrafter Blackfuse^ besiegt habt, springt zurück in das Rohr in Richtung Raumeingang. Folgt dem Weg nach Südwesten zurück.",
    ["After defeating ^Sisters of the Moon^, leave the boss room and take a left. Follow the winding path back to ^The Desolate Host^."] = "Nachdem Ihr ^Sisters of the Moon^ besiegt habt, verlasst den Bossraum und biegt links ab. Folgt dem gewundenen Weg zurück zu ^The Desolate Host^.",
    ["After defeating ^Sivara^, continue past her towards the map exit labeled ^Halls of the Chosen^. Take the underwater tunnel to reach the next area."] = "Nachdem Ihr ^Sivara^ besiegt habt, geht an ihr vorbei zum Kartenausgang mit der Bezeichnung ^Halls of the Chosen^. Nehmt den Unterwassertunnel in den nächsten Bereich.",
    ["After defeating ^Skolex^, follow the ring path up and around to ^Artificer Xy'mox^."] = "Nachdem Ihr ^Skolex^ besiegt habt, folgt dem Ringweg hinauf und herum zu ^Artificer Xy'mox^.",
    ["After defeating ^Skorpyron^, take the new southeast exit up the ramp and make your way towards ^Chronomatic Anomaly^. Kill trash on the way to open the door."] = "Nachdem Ihr ^Skorpyron^ besiegt habt, nehmt den neuen südöstlichen Ausgang die Rampe hinauf und begebt euch zu ^Chronomatic Anomaly^. Tötet unterwegs die Gegner, um die Tür zu öffnen.",
    ["After defeating ^Socrethar the Eternal^, leave the room to the south. In the next room, click 4x ^Demon Portals^ then kill ^Lord Aram'el^ to open the door. Proceed along the path to ^Tyrant Velhari^."] = "Nachdem Ihr ^Socrethar the Eternal^ besiegt habt, verlasst den Raum nach Süden. Klickt im nächsten Raum 4x auf ^Demon Portals^ und tötet anschließend ^Lord Aram'el^, um die Tür zu öffnen. Folgt dem Weg zu ^Tyrant Velhari^.",
    ["After defeating ^Star Augur Etraeus^, backtrack down the stairs to return to ^Astromancer's Rise^."] = "Nachdem Ihr ^Star Augur Etraeus^ besiegt habt, geht die Treppen zurück hinunter nach ^Astromancer's Rise^.",
    ["After defeating ^Stormwall Blockade^, walk onto the newly-arrived ship and speak with ^Captain Zadari^ to begin the ^Lady Jaina Proudmoore^ encounter."] = "Nachdem Ihr ^Stormwall Blockade^ besiegt habt, geht auf das neu angekommene Schiff und sprecht mit ^Captain Zadari^, um die Begegnung mit ^Lady Jaina Proudmoore^ zu beginnen.",
    ["After defeating ^Sun King's Salvation^, go back the way you came and return down the stairs to ^Halls of the Faithful^."] = "Nachdem Ihr ^Sun King's Salvation^ besiegt habt, geht auf demselben Weg zurück und die Treppen hinunter nach ^Halls of the Faithful^.",
    ["After defeating ^Tectus^, follow the path northeast to reach ^Brackenspore^."] = "Nachdem Ihr ^Tectus^ besiegt habt, folgt dem Weg nach Nordosten zu ^Brackenspore^.",
    ["After defeating ^Tectus^, leave his area and take a left to reach a portal."] = "Nachdem Ihr ^Tectus^ besiegt habt, verlasst seinen Bereich und biegt links zum Portal ab.",
    ["After defeating ^The Blast Furnace^, go straight ahead back up the spiral ramp. When you reach the bridge area, take a right and go up another ramp towards the main lobby."] = "Nachdem Ihr ^The Blast Furnace^ besiegt habt, geht geradeaus die spiralförmige Rampe wieder hinauf. Biegt im Brückenbereich rechts ab und folgt einer weiteren Rampe zur Haupthalle.",
    ["After defeating ^The Butcher^, take the western exit out of his area and follow the path north to ^Brackenspore^."] = "Nachdem Ihr ^The Butcher^ besiegt habt, nehmt den westlichen Ausgang aus seinem Bereich und folgt dem Weg nach Norden zu ^Brackenspore^.",
    ["After defeating ^The Coven of Shivarra^, take some stairs out of the area and make your way west towards the map exit labeled ^The World Soul^."] = "Nachdem Ihr ^The Coven of Shivarra^ besiegt habt, verlasst den Bereich über die Treppen und begebt euch nach Westen zum Kartenausgang mit der Bezeichnung ^The World Soul^.",
    ["After defeating ^The Demonic Inquisition^, follow the path to ^Terrace of the Moon^."] = "Nachdem Ihr ^The Demonic Inquisition^ besiegt habt, folgt dem Weg zu ^Terrace of the Moon^.",
    ["After defeating ^The Fallen Protectors^, follow the path to the mineshaft. Kill ^Zeal^ to unlock the way."] = "Nachdem Ihr ^The Fallen Protectors^ besiegt habt, folgt dem Weg zum Minenschacht. Tötet ^Zeal^, um den Weg freizuschalten.",
    ["After defeating ^The Forgotten Experiments^, jump down behind them (under a chain) and take the path across the room to the exit labeled ^Defiant Ramparts^."] = "Nachdem Ihr ^The Forgotten Experiments^ besiegt habt, springt hinter ihnen unter einer Kette hinab und folgt dem Weg durch den Raum zum Ausgang mit der Bezeichnung ^Defiant Ramparts^.",
    ["After defeating ^The Queen's Court^, head up some stairs towards the map exit labeled ^Precipice of Dreams^."] = "Nachdem Ihr ^The Queen's Court^ besiegt habt, geht die Treppen hinauf zum Kartenausgang mit der Bezeichnung ^Precipice of Dreams^.",
    ["After defeating ^The Restless Cabal^, there will be a cutscene where you will fall into a deep hole, landing in ^Tendril of Corruption^. Follow the path all the way back to reach ^Uu'nat^."] = "Nachdem Ihr ^The Restless Cabal^ besiegt habt, fallt Ihr in einer Zwischensequenz in ein tiefes Loch und landet in ^Tendril of Corruption^. Folgt dem Weg bis zurück zu ^Uu'nat^.",
    ["After defeating ^The Spirit Kings^, go downstairs to the previous room and take the new path by ^Lorewalker Cho^."] = "Nachdem Ihr ^The Spirit Kings^ besiegt habt, geht die Treppe in den vorherigen Raum hinunter und nehmt den neuen Weg bei ^Lorewalker Cho^.",
    ["After defeating ^The Stone Guard^, continue ahead to several trash packs with glowing orbs floating near them. Physically walk into the adds to spawn the trash. Once they're down, you can engage ^Feng the Accursed^."] = "Nachdem Ihr ^The Stone Guard^ besiegt habt, geht weiter zu mehreren Gegnergruppen, neben denen leuchtende Kugeln schweben. Lauft direkt in die Gegner hinein, damit die Gruppen erscheinen. Sobald sie besiegt sind, könnt Ihr ^Feng the Accursed^ angreifen.",
    ["After defeating ^Thok^, backtrack all the way past ^Spoils of Pandaria^ to arrive back in ^Underhold Nexus^."] = "Nachdem Ihr ^Thok^ besiegt habt, kehrt vollständig an ^Spoils of Pandaria^ vorbei nach ^Underhold Nexus^ zurück.",
    ["After defeating ^Tortos^, walk through him to reach the next area. To spawn ^Megaera^, you must destroy the (3) bells marked on the map, which are protected by ^Eternal Guardians^."] = "Nachdem Ihr ^Tortos^ besiegt habt, geht durch ihn hindurch in den nächsten Bereich. Damit ^Megaera^ erscheint, müsst Ihr die (3) auf der Karte markierten Glocken zerstören, die von ^Eternal Guardians^ bewacht werden.",
    ["After defeating ^Trilliax^, take the northwest exit out of the room and make your way up the spiral staircase."] = "Nachdem Ihr ^Trilliax^ besiegt habt, nehmt den nordwestlichen Ausgang und geht die Wendeltreppe hinauf.",
    ["After defeating ^Tsulong^, keep moving straight ahead and kill the trash to spawn ^Lei Shi^."] = "Nachdem Ihr ^Tsulong^ besiegt habt, geht geradeaus weiter und tötet die Gegner, damit ^Lei Shi^ erscheint.",
    ["After defeating ^Twin Ogron^, proceed up the stairwell behind them to reach ^Ko'ragh^. Clear trash to start the encounter."] = "Nachdem Ihr ^Twin Ogron^ besiegt habt, geht das Treppenhaus hinter ihnen hinauf zu ^Ko'ragh^. Beseitigt die Gegner, um die Begegnung zu beginnen.",
    ["After defeating ^Ultraxion^, wait for the cutscene, then board the ship and talk to ^Sky Captain Swayze^ to advance."] = "Nachdem Ihr ^Ultraxion^ besiegt habt, wartet die Zwischensequenz ab, geht an Bord des Schiffs und sprecht mit ^Sky Captain Swayze^, um fortzufahren.",
    ["After defeating ^Varimathras^, take the ascending stairwell out of the room towards ^Temple of Anguish^."] = "Nachdem Ihr ^Varimathras^ besiegt habt, nehmt das aufwärtsführende Treppenhaus aus dem Raum in Richtung ^Temple of Anguish^.",
    ["After defeating ^Warlord Zon'ozz^, return to ^Wyrmrest Temple^ by clicking the ^Portal^."] = "Nachdem Ihr ^Warlord Zon'ozz^ besiegt habt, kehrt zum ^Wyrmrest Temple^ zurück, indem Ihr auf das ^Portal^ klickt.",
    ["After defeating ^Wind Lord Mel'jarak^, take the southern stairwell and follow the linear path all the way to ^Amber-Shaper Un'sok^."] = "Nachdem Ihr ^Wind Lord Mel'jarak^ besiegt habt, nehmt das südliche Treppenhaus und folgt dem geradlinigen Weg bis zu ^Amber-Shaper Un'sok^.",
    ["After defeating ^Wrathion^, proceed through the long northern path to the map exit labeled ^Ny'alotha^. Take the elevator up, and continue through the door ahead."] = "Nachdem Ihr ^Wrathion^ besiegt habt, folgt dem langen nördlichen Weg zum Kartenausgang mit der Bezeichnung ^Ny'alotha^. Fahrt mit dem Aufzug hinauf und geht durch die Tür vor euch.",
    ["After defeating ^Wrathion^, you can proceed up the long bridge straight to ^Carapace of N'Zoth^."] = "Nachdem Ihr ^Wrathion^ besiegt habt, könnt Ihr über die lange Brücke direkt zu ^Carapace of N'Zoth^ weitergehen.",
    ["After defeating ^Yor'sahj^, return to ^Wyrmrest Temple^ by clicking the ^Portal^."] = "Nachdem Ihr ^Yor'sahj^ besiegt habt, kehrt zum ^Wyrmrest Temple^ zurück, indem Ihr auf das ^Portal^ klickt.",
    ["After defeating ^Zskarn^, drop down into the hole behind ^Neltharion^. Leap down again (across some lava), and make your way to the boss platform. Clear the trash to spawn ^Magmorax^."] = "Nachdem Ihr ^Zskarn^ besiegt habt, springt in das Loch hinter ^Neltharion^. Springt auf der anderen Seite der Lava erneut hinab und begebt euch zur Bossplattform. Beseitigt die Gegner, damit ^Magmorax^ erscheint.",
    ["After defeating the ^Ascendant Council^, continue down the southern path until you reach ^Cho'gall^."] = "Nachdem Ihr ^Ascendant Council^ besiegt habt, folgt dem südlichen Weg bis zu ^Cho'gall^.",
    ["After defeating the ^Assault of the Zaqali^, enter the nearby room labeled ^Molten Crucible^."] = "Nachdem Ihr ^Assault of the Zaqali^ besiegt habt, betretet den nahe gelegenen Raum mit der Bezeichnung ^Molten Crucible^.",
    ["After defeating the ^Champion of the Light^, follow the linear path to the right and work your way towards the next boss, ^Jadefire Masters^. Kill the final trash pack before running up the stairs."] = "Nachdem Ihr ^Champion of the Light^ besiegt habt, folgt dem geradlinigen Weg nach rechts bis zum nächsten Boss, ^Jadefire Masters^. Tötet die letzte Gegnergruppe, bevor Ihr die Treppe hinauflauft.",
    ["After defeating the ^Dragons of Nightmare^, go back the way you came and return to ^Core of the Nightmare^."] = "Nachdem Ihr ^Dragons of Nightmare^ besiegt habt, kehrt auf demselben Weg nach ^Core of the Nightmare^ zurück.",
    ["After defeating the ^Felhounds of Sargeras^, click the ^Lightforged Teleportation Pad^ in their boss room to be teleported further up the path. After landing, proceed ahead to ride the elevator up."] = "Nachdem Ihr ^Felhounds of Sargeras^ besiegt habt, klickt im Bossraum auf das ^Lightforged Teleportation Pad^, um weiter oben auf dem Weg teleportiert zu werden. Geht nach der Landung weiter und fahrt mit dem Aufzug nach oben.",
    ["After defeating the ^Hellfire High Council^, take the southwestern exit out of the room and follow the long linear path to ^Kilrogg Deadeye^."] = "Nachdem Ihr ^Hellfire High Council^ besiegt habt, nehmt den südwestlichen Ausgang und folgt dem langen geradlinigen Weg zu ^Kilrogg Deadeye^.",
    ["After defeating the ^Omnotron Defense System^, go back downstairs and proceed straight ahead to reach ^Magmaw^."] = "Nachdem Ihr ^Omnotron Defense System^ besiegt habt, geht die Treppe zurück hinunter und geradeaus zu ^Magmaw^.",
    ["After defeating the ^Paragons of the Klaxxi^, take the new exit on the south side of the room. As you approach ^Garrosh^, pull the hallway trash with you and most of the dialog will be skipped!"] = "Nachdem Ihr ^Paragons of the Klaxxi^ besiegt habt, nehmt den neuen Ausgang auf der Südseite des Raums. Zieht auf dem Weg zu ^Garrosh^ die Gegner im Gang mit euch, um den größten Teil des Dialogs zu überspringen!",
    ["After defeating the ^Spine of Deathwing^, talk to ^Thrall^ (twice) to begin the final battle with ^Madness of Deathwing^."] = "Nachdem Ihr ^Spine of Deathwing^ besiegt habt, sprecht zweimal mit ^Thrall^, um den letzten Kampf gegen ^Madness of Deathwing^ zu beginnen.",
    ["After finishing the adds, proceed forward and defeat ^MOTHER^."] = "Nachdem Ihr die Gegner erledigt habt, geht weiter und besiegt ^MOTHER^.",
    ["After getting off the elevator in ^Walk of Kings^, follow the linear path around to ^The Heart of the Empire^."] = "Nachdem Ihr den Aufzug in ^Walk of Kings^ verlassen habt, folgt dem geradlinigen Weg bis zu ^The Heart of the Empire^.",
    ["After getting off the elevator, follow the path around to the map exit labeled ^The Heart of the Empire^."] = "Nachdem Ihr den Aufzug verlassen habt, folgt dem Weg zum Kartenausgang mit der Bezeichnung ^The Heart of the Empire^.",
    ["After jumping in the hole, engage ^The Fallen Protectors^."] = "Nachdem Ihr in das Loch gesprungen seid, greift ^The Fallen Protectors^ an.",
    ["After jumping in the hole, follow the path straight ahead to find ^Harjatan^."] = "Nachdem Ihr in das Loch gesprungen seid, folgt dem Weg geradeaus zu ^Harjatan^.",
    ["After jumping in the hole, you will be in ^Chamber of Anguish^. Proceed to the next room to find ^Varimathras^."] = "Nachdem Ihr in das Loch gesprungen seid, befindet Ihr euch in ^Chamber of Anguish^. Geht in den nächsten Raum zu ^Varimathras^.",
    ["After killing ^Alizabal^, visit the final wing on the west to defeat ^Occu'thar^."] = "Nachdem Ihr ^Alizabal^ getötet habt, besucht den letzten Flügel im Westen und besiegt ^Occu'thar^.",
    ["After killing ^Antoran High Command^, kill yourself by jumping down the elevator hole to save time getting to the next boss."] = "Nachdem Ihr ^Antoran High Command^ getötet habt, springt in den Aufzugsschacht und sterbt, um auf dem Weg zum nächsten Boss Zeit zu sparen.",
    ["After killing ^Atramedes^, go back out to the main ring and head to the western ring to fight ^Chimaeron^."] = "Nachdem Ihr ^Atramedes^ getötet habt, kehrt zum Hauptring zurück und begebt euch zum westlichen Ring, um gegen ^Chimaeron^ zu kämpfen.",
    ["After killing ^Baleroc^, interact with the ^Magma Orb^ behind him to open the bridge. Cross the bridge and kill the trash to engage ^Majordomo Staghelm^."] = "Nachdem Ihr ^Baleroc^ getötet habt, interagiert mit der ^Magma Orb^ hinter ihm, um die Brücke zu öffnen. Überquert die Brücke und tötet die Gegner, um ^Majordomo Staghelm^ anzugreifen.",
    ["After killing ^Beastlord Darmac^, leave the room and take a right. Follow the path north to reach ^Operator Thogar^. To open the gate and start the fight, kill trash on both platforms, then kill the gunners on the train that pulls up."] = "Nachdem Ihr ^Beastlord Darmac^ getötet habt, verlasst den Raum und biegt rechts ab. Folgt dem Weg nach Norden zu ^Operator Thogar^. Tötet die Gegner auf beiden Plattformen und anschließend die Schützen auf dem einfahrenden Zug, um das Tor zu öffnen und den Kampf zu beginnen.",
    ["After killing ^Behemoth^, swim back out the way you came to the map exit labeled ^Halls of the Chosen^."] = "Nachdem Ihr ^Behemoth^ getötet habt, schwimmt auf demselben Weg zurück zum Kartenausgang mit der Bezeichnung ^Halls of the Chosen^.",
    ["After killing ^Blade Lord Ta'yak^, take the long stairwell exit on the west side of the room."] = "Nachdem Ihr ^Blade Lord Ta'yak^ getötet habt, nehmt das lange Treppenhaus auf der Westseite des Raums.",
    ["After killing ^Broodkeeper Diurna^, click any nearby dragon to fly to the ^Vault of the Incarnates^."] = "Nachdem Ihr ^Broodkeeper Diurna^ getötet habt, klickt auf einen beliebigen Drachen in der Nähe, um zu ^Vault of the Incarnates^ zu fliegen.",
    ["After killing ^Carapace^, you will find yourself standing in front of ^N'Zoth^. Attack the boss to start the encounter."] = "Nachdem Ihr ^Carapace^ getötet habt, steht Ihr direkt vor ^N'Zoth^. Greift den Boss an, um die Begegnung zu beginnen.",
    ["After killing ^Cenarius^, jump into the portal behind him to reach the ^Rift of Aln^."] = "Nachdem Ihr ^Cenarius^ getötet habt, springt in das Portal hinter ihm, um ^Rift of Aln^ zu erreichen.",
    ["After killing ^Chronomatic Anomaly^, proceed up the stairwell at the northwest side of the room, and clear slimes in the boss room to engage ^Trilliax^."] = "Nachdem Ihr ^Chronomatic Anomaly^ getötet habt, nehmt das Treppenhaus an der Nordwestseite des Raums und beseitigt die Schleime im Bossraum, um ^Trilliax^ anzugreifen.",
    ["After killing ^Council of Blood^, take the south stairwell out of the room and return to the ^Halls of the Faithful^."] = "Nachdem Ihr ^Council of Blood^ getötet habt, nehmt das südliche Treppenhaus aus dem Raum und kehrt zu ^Halls of the Faithful^ zurück.",
    ["After killing ^Council of Dreams^, follow the path behind them to reach ^Nymue, Weaver of the Cycle^."] = "Nachdem Ihr ^Council of Dreams^ getötet habt, folgt dem Weg hinter ihnen zu ^Nymue, Weaver of the Cycle^.",
    ["After killing ^Dathea, Ascended^, take one of the nearby ^Downward Draft^ to return below to ^The Primal Bulwark^."] = "Nachdem Ihr ^Dathea, Ascended^ getötet habt, benutzt einen der nahe gelegenen ^Downward Draft^, um nach unten zu ^The Primal Bulwark^ zurückzukehren.",
    ["After killing ^Dausegne^, continue up the path toward ^The Endless Foundry^."] = "Nachdem Ihr ^Dausegne^ getötet habt, folgt dem Weg hinauf in Richtung ^The Endless Foundry^.",
    ["After killing ^Drest'agath^, leave the room and continue down the spiral toward the map exit ^Chamber of Rebirth^."] = "Nachdem Ihr ^Drest'agath^ getötet habt, verlasst den Raum und folgt der Spirale hinab zum Kartenausgang ^Chamber of Rebirth^.",
    ["After killing ^Elegon^, follow the path out of the room and head south to arrive at the next boss room. To start the fight with ^Will of the Emperor^, click the pipes below (^Heroic^) or click the console (^Normal/LFR^)."] = "Nachdem Ihr ^Elegon^ getötet habt, folgt dem Weg aus dem Raum und geht nach Süden zum nächsten Bossraum. Beginnt den Kampf gegen ^Will of the Emperor^, indem Ihr auf die Rohre unten (^Heroic^) oder auf die Konsole (^Normal/LFR^) klickt.",
    ["After killing ^Eranog^, click the ^Clutchwarren Runestone^ next to each staircase. After that, take the staircase towards ^The Clutchwarren^."] = "Nachdem Ihr ^Eranog^ getötet habt, klickt neben jeder Treppe auf den ^Clutchwarren Runestone^. Nehmt danach die Treppe in Richtung ^The Clutchwarren^.",
    ["After killing ^Eranog^, take the left map exit labeled ^The Elemental Conclave^."] = "Nachdem Ihr ^Eranog^ getötet habt, nehmt den linken Kartenausgang mit der Bezeichnung ^The Elemental Conclave^.",
    ["After killing ^Eranog^, there are 3 paths available. Take the path on the right labeled ^The Vault Approach^."] = "Nachdem Ihr ^Eranog^ getötet habt, stehen 3 Wege zur Auswahl. Nehmt den rechten Weg mit der Bezeichnung ^The Vault Approach^.",
    ["After killing ^Eranog^, you will find two clickable runes beside the stairs leading to ^Broodkeeper Diurna^. Click the runes to open the access."] = "Nachdem Ihr ^Eranog^ getötet habt, findet Ihr neben der Treppe zu ^Broodkeeper Diurna^ zwei anklickbare Runen. Klickt auf die Runen, um den Zugang zu öffnen.",
    ["After killing ^Fallen Avatar^, continue straight ahead across the slime to the map exit labeled ^The Twisting Nether^. Walk into the green swirly portal."] = "Nachdem Ihr ^Fallen Avatar^ getötet habt, geht geradeaus durch den Schleim zum Kartenausgang mit der Bezeichnung ^The Twisting Nether^. Lauft in das grüne wirbelnde Portal.",
    ["After killing ^Fatescribe Roh-Kalo^, go back out the way you came and follow the path to ^Kel'Thuzad^."] = "Nachdem Ihr ^Fatescribe Roh-Kalo^ getötet habt, geht auf demselben Weg zurück und folgt dem Weg zu ^Kel'Thuzad^.",
    ["After killing ^Feng^, continue on to the next area."] = "Nachdem Ihr ^Feng^ getötet habt, geht in den nächsten Bereich weiter.",
    ["After killing ^Fetid Devourer^, go back the way you came to arrive back in the ^Ring of Containment^."] = "Nachdem Ihr ^Fetid Devourer^ getötet habt, kehrt auf demselben Weg zu ^Ring of Containment^ zurück.",
    ["After killing ^Galakras^, follow the long path to the west until you arrive at ^Iron Juggernaut^."] = "Nachdem Ihr ^Galakras^ getötet habt, folgt dem langen Weg nach Westen, bis Ihr ^Iron Juggernaut^ erreicht.",
    ["After killing ^Gara'jal^, follow the linear path to ^Lorewalker Cho^. Speak to him to trigger a series of trash encounters."] = "Nachdem Ihr ^Gara'jal^ getötet habt, folgt dem geradlinigen Weg zu ^Lorewalker Cho^. Sprecht mit ihm, um eine Reihe von Kämpfen gegen Gegner zu starten.",
    ["After killing ^Garalon^, walk up the stairs behind you to find ^Wind Lord Mel'jarak^."] = "Nachdem Ihr ^Garalon^ getötet habt, geht die Treppe hinter euch hinauf zu ^Wind Lord Mel'jarak^.",
    ["After killing ^Garothi Worldbreaker^, you can take the teleporter to whichever skip you have unlocked:\n  - The Exhaust: ^Imonar the Soulhunter^\n  - The Burning Throne: ^Aggramar^\n\nNote: RetroRuns only has the route built for Aggramar at this time."] = "Nachdem Ihr ^Garothi Worldbreaker^ getötet habt, könnt Ihr den Teleporter zu jeder freigeschalteten Abkürzung nehmen:\n  - Der Abgasschacht: ^Imonar the Soulhunter^\n  - Der Brennende Thron: ^Aggramar^\n\nHinweis: RetroRuns enthält derzeit nur die Route für Aggramar.",
    ["After killing ^Gnarlroot^ and ^Igira^, you can channel the seed to open the bridge to ^Smolderon^."] = "Nachdem Ihr ^Gnarlroot^ und ^Igira^ getötet habt, könnt Ihr den Samen kanalisieren, um die Brücke zu ^Smolderon^ zu öffnen.",
    ["After killing ^Gnarlroot^, continue forward and clear the trash pack to start the encounter with ^Igira the Cruel^."] = "Nachdem Ihr ^Gnarlroot^ getötet habt, geht weiter und beseitigt die Gegnergruppe, um die Begegnung mit ^Igira the Cruel^ zu beginnen.",
    ["After killing ^Gorefiend^, click the nearby portal."] = "Nachdem Ihr ^Gorefiend^ getötet habt, klickt auf das nahe gelegene Portal.",
    ["After killing ^Goroth^, go down the staircase behind ^Image of Aegwynn^."] = "Nachdem Ihr ^Goroth^ getötet habt, geht die Treppe hinter ^Image of Aegwynn^ hinunter.",
    ["After killing ^Goroth^, take the western exit labeled ^The Abyssal Throne^."] = "Nachdem Ihr ^Goroth^ getötet habt, nehmt den westlichen Ausgang mit der Bezeichnung ^The Abyssal Throne^.",
    ["After killing ^Goroth^, the door behind ^Image of Aegwynn^ opens, allowing you to skip to ^Maiden of Vigilance^."] = "Nachdem Ihr ^Goroth^ getötet habt, öffnet sich die Tür hinter ^Image of Aegwynn^ und ermöglicht eine Abkürzung zu ^Maiden of Vigilance^.",
    ["After killing ^Grong^, continue up the stairwell behind him towards the map exit labeled ^Halls of Opulence^. Jump in the hole when you reach the end of the path."] = "Nachdem Ihr ^Grong^ getötet habt, geht das Treppenhaus hinter ihm hinauf zum Kartenausgang mit der Bezeichnung ^Halls of Opulence^. Springt am Ende des Weges in das Loch.",
    ["After killing ^Gruul^, backtrack to the bridge and go east. Follow the spiral down, then at the bottom go straight ahead to locate ^The Blast Furnace^."] = "Nachdem Ihr ^Gruul^ getötet habt, kehrt zur Brücke zurück und geht nach Osten. Folgt der Spirale nach unten und geht unten geradeaus zu ^The Blast Furnace^.",
    ["After killing ^Guardian of the First Ones^, go back the way you came and follow the path to ^Fatescribe Roh-Kalo^. For a shortcut, you can jump off the ledge to respawn halfway there."] = "Nachdem Ihr ^Guardian of the First Ones^ getötet habt, kehrt auf demselben Weg zurück und folgt dem Weg zu ^Fatescribe Roh-Kalo^. Als Abkürzung könnt Ihr vom Vorsprung springen und auf halber Strecke wiedererscheinen.",
    ["After killing ^Guarm^, continue down the path to meet ^Helya^. Kill the trash to start the encounter."] = "Nachdem Ihr ^Guarm^ getötet habt, folgt dem Weg zu ^Helya^. Tötet die Gegner, um die Begegnung zu beginnen.",
    ["After killing ^Halondrus^, continue down the path behind him to reach his loot chest. Activate the nearby teleporter and select ^Genesis Cradle Alpha^."] = "Nachdem Ihr ^Halondrus^ getötet habt, folgt dem Weg hinter ihm zu seiner Beutetruhe. Aktiviert den nahe gelegenen Teleporter und wählt ^Genesis Cradle Alpha^.",
    ["After killing ^Hans'gar and Franzok^, take the southern exit out of the room. Follow the path across the next room to reach ^Flamebender Ka'graz^."] = "Nachdem Ihr ^Hans'gar and Franzok^ getötet habt, nehmt den südlichen Ausgang. Durchquert den nächsten Raum zu ^Flamebender Ka'graz^.",
    ["After killing ^Harjatan^, jump over the ledge to his left and land in the water. Follow the path through the tunnel and continue straight ahead to find ^Mistress Sassz'ine^."] = "Nachdem Ihr ^Harjatan^ getötet habt, springt über den Vorsprung links von ihm ins Wasser. Folgt dem Weg durch den Tunnel und geht geradeaus weiter zu ^Mistress Sassz'ine^.",
    ["After killing ^Horridon^, go through the north exit and follow the path all the way to ^Council of Elders^. Kill trash to unlock doors along the way."] = "Nachdem Ihr ^Horridon^ getötet habt, nehmt den nördlichen Ausgang und folgt dem Weg bis zu ^Council of Elders^. Tötet unterwegs Gegner, um die Türen zu entriegeln.",
    ["After killing ^Hungering Destroyer^, take the stairs going up to ^The Purloined Stores^."] = "Nachdem Ihr ^Hungering Destroyer^ getötet habt, nehmt die Treppe hinauf zu ^The Purloined Stores^.",
    ["After killing ^Huntsman Altimor^, follow the path to a small room at the back, and jump into the sewer that the NPCs are standing next to. Make your way down the path to find ^Hungering Destroyer^."] = "Nachdem Ihr ^Huntsman Altimor^ getötet habt, folgt dem Weg zu einem kleinen Raum hinten und springt in den Abwasserkanal neben den NPCs. Folgt dem Weg nach unten zu ^Hungering Destroyer^.",
    ["After killing ^Igira the Cruel^, go up the stairs behind him and channel the ^Formation Seed^ to form the bridge."] = "Nachdem Ihr ^Igira the Cruel^ getötet habt, geht die Treppe hinter ihm hinauf und kanalisiert den ^Formation Seed^, um die Brücke zu bilden.",
    ["After killing ^Igira^, take the left exit to ^The Scorched Hall^."] = "Nachdem Ihr ^Igira^ getötet habt, nehmt den linken Ausgang nach ^The Scorched Hall^.",
    ["After killing ^Il'gynoth^, return back the way you came, through the portal to ^Core of the Nightmare^."] = "Nachdem Ihr ^Il'gynoth^ getötet habt, kehrt auf demselben Weg durch das Portal nach ^Core of the Nightmare^ zurück.",
    ["After killing ^Imonar^, make your way down the long path to find the next boss, ^Kin'garoth^."] = "Nachdem Ihr ^Imonar^ getötet habt, folgt dem langen Weg zum nächsten Boss, ^Kin'garoth^.",
    ["After killing ^Iron Juggernaut^, head into the ^Gates of Orgrimmar^."] = "Nachdem Ihr ^Iron Juggernaut^ getötet habt, begebt euch zu ^Gates of Orgrimmar^.",
    ["After killing ^Iron Reaver^, continue up the stairs behind him to the next area."] = "Nachdem Ihr ^Iron Reaver^ getötet habt, geht die Treppe hinter ihm hinauf in den nächsten Bereich.",
    ["After killing ^Ji-Kun^, click a feather followed by your Extra Action Button to fly to the southwest exit of the room."] = "Nachdem Ihr ^Ji-Kun^ getötet habt, klickt auf eine Feder und anschließend auf Eure Extraaktionsschaltfläche, um zum südwestlichen Ausgang des Raums zu fliegen.",
    ["After killing ^Jin'rokh^, take the long path south and cross two bridges before arriving in the next area. Avoid blue circles; they will throw you off the edge."] = "Nachdem Ihr ^Jin'rokh^ getötet habt, folgt dem langen Weg nach Süden und überquert zwei Brücken zum nächsten Bereich. Meidet die blauen Kreise, da sie euch über den Rand schleudern.",
    ["After killing ^Kargath^, exit the room to the northwest and follow the path around to ^The Butcher^."] = "Nachdem Ihr ^Kargath^ getötet habt, verlasst den Raum nach Nordwesten und folgt dem Weg zu ^The Butcher^.",
    ["After killing ^Kazzara^, take the left path towards the exit labeled ^Onyx Laboratory^."] = "Nachdem Ihr ^Kazzara^ getötet habt, nehmt den linken Weg zum Ausgang mit der Bezeichnung ^Onyx Laboratory^.",
    ["After killing ^Kel'Thuzad^, take the purple portal that appeared right behind him."] = "Nachdem Ihr ^Kel'Thuzad^ getötet habt, nehmt das violette Portal, das direkt hinter ihm erschienen ist.",
    ["After killing ^Kilrogg Deadeye^, exit behind him to the east and follow the path out of this area."] = "Nachdem Ihr ^Kilrogg Deadeye^ getötet habt, verlasst den Bereich hinter ihm nach Osten und folgt dem Weg hinaus.",
    ["After killing ^Kin'garoth^, click the ^Lightforged Beacon^ behind you to be teleported to the next area. Select ^The Burning Throne^ from the dialog options."] = "Nachdem Ihr ^Kin'garoth^ getötet habt, klickt hinter euch auf das ^Lightforged Beacon^, um in den nächsten Bereich teleportiert zu werden. Wählt im Dialog ^The Burning Throne^.",
    ["After killing ^Ko'ragh^, take the northwest stairwell out of the room."] = "Nachdem Ihr ^Ko'ragh^ getötet habt, nehmt das nordwestliche Treppenhaus aus dem Raum.",
    ["After killing ^Kor'kron Dark Shaman^, follow the northeastern path towards ^The Drag^. Clear trash and enter the ^Cleft of Shadows^."] = "Nachdem Ihr ^Kor'kron Dark Shaman^ getötet habt, folgt dem nordöstlichen Weg in Richtung ^The Drag^. Beseitigt die Gegner und betretet ^Cleft of Shadows^.",
    ["After killing ^Kormrok^, exit the room the way you entered."] = "Nachdem Ihr ^Kormrok^ getötet habt, verlasst den Raum auf demselben Weg.",
    ["After killing ^Kromog^, exit the room to the east and follow the path to the elevator."] = "Nachdem Ihr ^Kromog^ getötet habt, verlasst den Raum nach Osten und folgt dem Weg zum Aufzug.",
    ["After killing ^Kurog Grimtotem^, follow the path back to ^The Vault Approach^."] = "Nachdem Ihr ^Kurog Grimtotem^ getötet habt, folgt dem Weg zurück zu ^The Vault Approach^.",
    ["After killing ^Lady Ashvane^, jump through the hole in the middle of her boss room to land in ^The Traverse^."] = "Nachdem Ihr ^Lady Ashvane^ getötet habt, springt durch das Loch in der Mitte ihres Bossraums und landet in ^The Traverse^.",
    ["After killing ^Lady Inerva Darkvein^, follow the path to take the exit ^General Draven^ is standing in. He will lead you back to the main entrance of the raid in ^The Grand Walk^."] = "Nachdem Ihr ^Lady Inerva Darkvein^ getötet habt, folgt dem Weg zu dem Ausgang, in dem ^General Draven^ steht. Er führt euch zum Haupteingang des Schlachtzugs in ^The Grand Walk^ zurück.",
    ["After killing ^Larodar^, interact with the ^Seed of Life^ to unlock a portal at the back of the room. Walk through the portal to arrive back at the ^Wellspring Atrium^."] = "Nachdem Ihr ^Larodar^ getötet habt, interagiert mit dem ^Seed of Life^, um hinten im Raum ein Portal freizuschalten. Geht durch das Portal zurück zu ^Wellspring Atrium^.",
    ["After killing ^Lei Shen^, click the ^Displacement Pad^ in the middle of the room to be teleported back to ^Primordius^' room."] = "Nachdem Ihr ^Lei Shen^ getötet habt, klickt in der Mitte des Raums auf das ^Displacement Pad^, um zurück in den Raum von ^Primordius^ teleportiert zu werden.",
    ["After killing ^Lord Rhyolith^, make your way north to reach ^Alysrazor^. Tag ^Majordomo^ to start the encounter."] = "Nachdem Ihr ^Lord Rhyolith^ getötet habt, geht nach Norden zu ^Alysrazor^. Greift ^Majordomo^ an, um die Begegnung zu beginnen.",
    ["After killing ^Lords of Dread^, you will find a teleporter behind them. Use it to take a shortcut back to the beginning of the room, and follow the path to ^Rygelon^."] = "Nachdem Ihr ^Lords of Dread^ getötet habt, findet Ihr hinter ihnen einen Teleporter. Benutzt ihn als Abkürzung zum Anfang des Raums und folgt dem Weg zu ^Rygelon^.",
    ["After killing ^Magmaw^, go back down the stairs to the main lobby. Take a left and ride the elevator down."] = "Nachdem Ihr ^Magmaw^ getötet habt, geht die Treppe zurück hinunter in die Haupthalle. Biegt links ab und fahrt mit dem Aufzug nach unten.",
    ["After killing ^Maiden of Vigilance^, click the nearby ^Teleportation Pad^ to be taken to ^Chamber of the Avatar^. Note: the pad will likely be under the boss corpse until she despawns, but you can still click it."] = "Nachdem Ihr ^Maiden of Vigilance^ getötet habt, klickt auf das nahe gelegene ^Teleportation Pad^, um nach ^Chamber of the Avatar^ gebracht zu werden. Hinweis: Die Plattform liegt wahrscheinlich unter der Leiche des Bosses, bis sie verschwindet, kann aber trotzdem angeklickt werden.",
    ["After killing ^Majordomo Staghelm^, proceed straight ahead all the way to ^Ragnaros^."] = "Nachdem Ihr ^Majordomo Staghelm^ getötet habt, geht geradeaus bis zu ^Ragnaros^.",
    ["After killing ^Malkorok^, take the northwestern exit from the platform and follow it around to kill the scorpion and click ^Release Lever^."] = "Nachdem Ihr ^Malkorok^ getötet habt, nehmt den nordwestlichen Ausgang von der Plattform, folgt ihm, tötet den Skorpion und klickt auf ^Release Lever^.",
    ["After killing ^Mannoroth^, click the nearby portal."] = "Nachdem Ihr ^Mannoroth^ getötet habt, klickt auf das nahe gelegene Portal.",
    ["After killing ^Maut^, take the long path all the way to the right to reach ^The Prophet Skitra^. Jump off the ledge and die for a shortcut."] = "Nachdem Ihr ^Maut^ getötet habt, folgt dem langen Weg ganz rechts zu ^The Prophet Skitra^. Springt für eine Abkürzung vom Vorsprung und sterbt.",
    ["After killing ^Nymue^, walk up the stairs behind her to interact with the ^Seed of Life^. This opens a portal at the back of the room. Walk through the portal to return back to ^Wellspring Atrium^."] = "Nachdem Ihr ^Nymue^ getötet habt, geht die Treppe hinter ihr hinauf und interagiert mit dem ^Seed of Life^. Dadurch öffnet sich hinten im Raum ein Portal. Geht hindurch, um zu ^Wellspring Atrium^ zurückzukehren.",
    ["After killing ^Opulence^, exit the room to the north, up some stairs to the map exit labeled ^Loa's Sanctum^."] = "Nachdem Ihr ^Opulence^ getötet habt, verlasst den Raum nach Norden und geht die Treppen hinauf zum Kartenausgang mit der Bezeichnung ^Loa's Sanctum^.",
    ["After killing ^Opulence^, follow the path straight ahead and make your way to the map exit labeled ^Loa's Sanctum^."] = "Nachdem Ihr ^Opulence^ getötet habt, folgt dem Weg geradeaus zum Kartenausgang mit der Bezeichnung ^Loa's Sanctum^.",
    ["After killing ^Oregorger^, leave his area the way you came and follow the path all the way north to find ^Gruul^."] = "Nachdem Ihr ^Oregorger^ getötet habt, verlasst den Bereich auf demselben Weg und folgt dem Weg ganz nach Norden zu ^Gruul^.",
    ["After killing ^Orgozoa^, travel to the far west to reach the map exit labeled ^The Queen's Court^. You will be swimming for a good portion of this journey."] = "Nachdem Ihr ^Orgozoa^ getötet habt, reist weit nach Westen zum Kartenausgang mit der Bezeichnung ^The Queen's Court^. Einen großen Teil des Weges müsst Ihr schwimmen.",
    ["After killing ^Painsmith Raznal^, walk out the new exit to the West and walk through the portal."] = "Nachdem Ihr ^Painsmith Raznal^ getötet habt, nehmt den neuen Ausgang im Westen und geht durch das Portal.",
    ["After killing ^Portal Keeper Hasabel^, return to the portal marked on the map as ^Light's Breach^."] = "Nachdem Ihr ^Portal Keeper Hasabel^ getötet habt, kehrt zum auf der Karte als ^Light's Breach^ markierten Portal zurück.",
    ["After killing ^Primordius^, take the western stairwell out of the room and follow it to ^Dark Animus^. Kill the ritualists to start the fight."] = "Nachdem Ihr ^Primordius^ getötet habt, nehmt das westliche Treppenhaus aus dem Raum und folgt ihm zu ^Dark Animus^. Tötet die Ritualisten, um den Kampf zu beginnen.",
    ["After killing ^Remnant of Ner'zhul^, follow the path to loop back around to ^Painsmith Raznal^."] = "Nachdem Ihr ^Remnant of Ner'zhul^ getötet habt, folgt dem Weg in einer Schleife zurück zu ^Painsmith Raznal^.",
    ["After killing ^Rygelon^, follow the path straight behind him all the way to ^The Jailer^."] = "Nachdem Ihr ^Rygelon^ getötet habt, folgt dem Weg direkt hinter ihm bis zu ^The Jailer^.",
    ["After killing ^Sennarth^, click the ^Gust of Wind^ behind him to return to the bottom of the room. If you killed him on the ground floor, proceed up the ramp to find his corpse and collect his loot!"] = "Nachdem Ihr ^Sennarth^ getötet habt, klickt hinter ihm auf den ^Gust of Wind^, um zum unteren Ende des Raums zurückzukehren. Falls Ihr ihn im Erdgeschoss getötet habt, geht die Rampe hinauf, um seine Leiche zu finden und die Beute einzusammeln!",
    ["After killing ^Shadow-Lord Iskar^, exit the room to the east. At the first intersection, go south to the next area."] = "Nachdem Ihr ^Shadow-Lord Iskar^ getötet habt, verlasst den Raum nach Osten. Geht an der ersten Kreuzung nach Süden in den nächsten Bereich.",
    ["After killing ^Shriekwing^, follow the north path out of the room and go down the stairs. Kill the trash, and ^General Draven^ will come open the gate. Kill a few trash mobs then engage ^Huntsman Altimor^."] = "Nachdem Ihr ^Shriekwing^ getötet habt, folgt dem nördlichen Weg aus dem Raum und geht die Treppe hinunter. Tötet die Gegner, damit ^General Draven^ das Tor öffnet. Tötet einige weitere Gegner und greift dann ^Huntsman Altimor^ an.",
    ["After killing ^Shriekwing^, speak to ^General Draven^ near the north exit to skip to ^Sludgefist^. He will spawn behind you in the normal location."] = "Nachdem Ihr ^Shriekwing^ getötet habt, sprecht beim nördlichen Ausgang mit ^General Draven^, um die Abkürzung zu ^Sludgefist^ zu nehmen. Er erscheint hinter euch an seiner normalen Position.",
    ["After killing ^Shriekwing^, there will be a lengthy dialog. After that, you can fight ^Sludgefist^ in the same room."] = "Nachdem Ihr ^Shriekwing^ getötet habt, folgt ein längerer Dialog. Danach könnt Ihr im selben Raum gegen ^Sludgefist^ kämpfen.",
    ["After killing ^Skitra^, backtrack a bit and go north to the map exit labeled ^Ny'alotha^. Ride an elevator up, and kill the trash to open the path to the next area."] = "Nachdem Ihr ^Skitra^ getötet habt, geht ein Stück zurück und nach Norden zum Kartenausgang mit der Bezeichnung ^Ny'alotha^. Fahrt mit dem Aufzug hinauf und tötet die Gegner, um den Weg in den nächsten Bereich zu öffnen.",
    ["After killing ^Sludgefist^, travel up the stairs behind him and walk through the mirror teleporter to land in ^Nightcloak Sanctum^."] = "Nachdem Ihr ^Sludgefist^ getötet habt, geht die Treppe hinter ihm hinauf und durch den Spiegelteleporter, um in ^Nightcloak Sanctum^ zu landen.",
    ["After killing ^Smolderon^, talk to the dragon to be flown to ^Tindral Sageswift, Seer of the Flame^."] = "Nachdem Ihr ^Smolderon^ getötet habt, sprecht mit dem Drachen, um zu ^Tindral Sageswift, Seer of the Flame^ geflogen zu werden.",
    ["After killing ^Soulrender Dormazain^, follow the path to ^Remnant of Ner'zhul^. Kill the trash to engage the boss."] = "Nachdem Ihr ^Soulrender Dormazain^ getötet habt, folgt dem Weg zu ^Remnant of Ner'zhul^. Tötet die Gegner, um den Boss anzugreifen.",
    ["After killing ^Stone Legion Generals^, simply walk into the room where ^Sire Denathrius^ is waiting for you."] = "Nachdem Ihr ^Stone Legion Generals^ getötet habt, geht einfach in den Raum, in dem ^Sire Denathrius^ auf euch wartet.",
    ["After killing ^Taloc^, the floor will start to descend. Once you reach the bottom, go straight ahead and click the ^Titan Console^."] = "Nachdem Ihr ^Taloc^ getötet habt, beginnt der Boden abzusinken. Geht unten geradeaus und klickt auf die ^Titan Console^.",
    ["After killing ^Tarragrue^, wait for dialog to complete, then walk through the portal marked as a map exit ^Shadowsteel Foundry^."] = "Nachdem Ihr ^Tarragrue^ getötet habt, wartet das Ende des Dialogs ab und geht dann durch das auf der Karte als Ausgang ^Shadowsteel Foundry^ markierte Portal.",
    ["After killing ^The Amalgamation Chamber^, follow the path north to reach some stairs leading to the ^Molten Crucible^."] = "Nachdem Ihr ^The Amalgamation Chamber^ getötet habt, folgt dem Weg nach Norden zu den Treppen, die nach ^Molten Crucible^ führen.",
    ["After killing ^The Butcher^, follow the path to the west to reach ^Tectus^. Kill the (3) rock golems to spawn the boss."] = "Nachdem Ihr ^The Butcher^ getötet habt, folgt dem Weg nach Westen zu ^Tectus^. Tötet die (3) Felsgolems, damit der Boss erscheint.",
    ["After killing ^The Eye of the Jailer^, follow the path all the way north to find ^The Nine^."] = "Nachdem Ihr ^The Eye of the Jailer^ getötet habt, folgt dem Weg ganz nach Norden zu ^The Nine^.",
    ["After killing ^The Hivemind^, continue past them to the next room, and take the elevator up to the ^Terrace of Desolation^."] = "Nachdem Ihr ^The Hivemind^ getötet habt, geht an ihnen vorbei in den nächsten Raum und fahrt mit dem Aufzug hinauf zu ^Terrace of Desolation^.",
    ["After killing ^The Nine^, take the elevator to the left. You will arrive at ^The Torment Chambers^."] = "Nachdem Ihr ^The Nine^ getötet habt, nehmt den Aufzug auf der linken Seite. Ihr gelangt nach ^The Torment Chambers^.",
    ["After killing ^The Primal Council^, follow the path towards the exit labeled ^Galewind Crag^. Kill ^Thondrozus^, and click on ^Upward Draft^ to be carried up to ^Galewind Crag^. Approach the Downward Draft."] = "Nachdem Ihr ^The Primal Council^ getötet habt, folgt dem Weg zum Ausgang mit der Bezeichnung ^Galewind Crag^. Tötet ^Thondrozus^ und klickt auf ^Upward Draft^, um nach ^Galewind Crag^ getragen zu werden. Nähert euch dem Abwind.",
    ["After killing ^The Tarragrue^, speak to the ^Ebon Blade Acolyte^ NPC located inside the boss room. He will conjure a portal that will send you straight to ^Kel'Thuzad^."] = "Nachdem Ihr ^The Tarragrue^ getötet habt, sprecht im Bossraum mit dem NPC ^Ebon Blade Acolyte^. Er beschwört ein Portal, das euch direkt zu ^Kel'Thuzad^ bringt.",
    ["After killing ^Theralion and Valiona^, head south and exit this area."] = "Nachdem Ihr ^Theralion and Valiona^ getötet habt, geht nach Süden und verlasst diesen Bereich.",
    ["After killing ^Tichondrius^, backtrack the way you came to return to the main courtyard."] = "Nachdem Ihr ^Tichondrius^ getötet habt, kehrt auf demselben Weg zum Haupthof zurück.",
    ["After killing ^Tindral^, mount up and fly into the fire-colored portal in the sky (marked with a |TInterface\\TargetingFrame\\UI-RaidTargetingIcon_1:0|t). This will teleport you to ^Heart of Amirdrassil^."] = "Nachdem Ihr ^Tindral^ getötet habt, steigt auf und fliegt in das feuerfarbene Portal am Himmel, das mit |TInterface\\TargetingFrame\\UI-RaidTargetingIcon_1:0|t markiert ist. Dadurch werdet Ihr nach ^Heart of Amirdrassil^ teleportiert.",
    ["After killing ^Tyrant Velhari^, leave the room to the west and proceed up the path to the north."] = "Nachdem Ihr ^Tyrant Velhari^ getötet habt, verlasst den Raum nach Westen und folgt dem Weg nach Norden hinauf.",
    ["After killing ^Ursoc^, go back the way you came and go back through the portal to ^Core of the Nightmare^."] = "Nachdem Ihr ^Ursoc^ getötet habt, kehrt auf demselben Weg durch das Portal nach ^Core of the Nightmare^ zurück.",
    ["After killing ^Vectis^, go back the way you came to arrive back in the ^Ring of Containment^."] = "Nachdem Ihr ^Vectis^ getötet habt, kehrt auf demselben Weg zu ^Ring of Containment^ zurück.",
    ["After killing ^Vexiona^, interact with the ^Re-origination Anchor^ behind the boss to be teleported. After you land, continue ahead."] = "Nachdem Ihr ^Vexiona^ getötet habt, interagiert hinter dem Boss mit dem ^Re-origination Anchor^, um teleportiert zu werden. Geht nach der Landung weiter.",
    ["After killing ^Vigilant Guardian^, proceed up the bridge and speak to ^Highlord Bolvar Fordragon^ and then take the portal to ^Domination's Grasp^."] = "Nachdem Ihr ^Vigilant Guardian^ getötet habt, geht die Brücke hinauf, sprecht mit ^Highlord Bolvar Fordragon^ und nehmt anschließend das Portal nach ^Domination's Grasp^.",
    ["After killing ^Vigilant Guardian^, proceed up the bridge and speak to ^Highlord Bolvar Fordragon^ near the teleporter to skip ahead to ^Anduin Wrynn^."] = "Nachdem Ihr ^Vigilant Guardian^ getötet habt, geht die Brücke hinauf und sprecht beim Teleporter mit ^Highlord Bolvar Fordragon^, um die Abkürzung zu ^Anduin Wrynn^ zu nehmen.",
    ["After killing ^Volcoross^, continue down the path behind him. Clear trash to start the encounter with ^Larodar, Keeper of the Flame^."] = "Nachdem Ihr ^Volcoross^ getötet habt, folgt dem Weg hinter ihm. Beseitigt die Gegner, um die Begegnung mit ^Larodar, Keeper of the Flame^ zu beginnen.",
    ["After killing ^Warmaster Blackhorn^, talk to ^Sky Captain Swayze^ to begin the encounter with ^Spine of Deathwing^."] = "Nachdem Ihr ^Warmaster Blackhorn^ getötet habt, sprecht mit ^Sky Captain Swayze^, um die Begegnung mit ^Spine of Deathwing^ zu beginnen.",
    ["After killing ^Wrathion^, take the path all the way to the left. Clear the room to spawn ^Maut^, and kill him."] = "Nachdem Ihr ^Wrathion^ getötet habt, nehmt den Weg ganz links. Beseitigt den Raum, damit ^Maut^ erscheint, und tötet ihn.",
    ["After killing ^Xanesh^, leave the room to the east and towards the map exit for ^Twilight Landing^. Ride the elevator up."] = "Nachdem Ihr ^Xanesh^ getötet habt, verlasst den Raum nach Osten in Richtung des Kartenausgangs für ^Twilight Landing^. Fahrt mit dem Aufzug hinauf.",
    ["After killing ^Xhul'horac^, head west out of the room the same way you came in."] = "Nachdem Ihr ^Xhul'horac^ getötet habt, verlasst den Raum auf demselben Weg nach Westen.",
    ["After killing ^Xhul'horac^, take the portal that appears right next to you."] = "Nachdem Ihr ^Xhul'horac^ getötet habt, nehmt das Portal, das direkt neben euch erscheint.",
    ["After killing ^Za'qul^, watch a brief dialog while waiting on a portal to spawn behind the boss. Take the portal, marked on the map as an exit labeled ^The Last Prison^."] = "Nachdem Ihr ^Za'qul^ getötet habt, wartet während eines kurzen Dialogs, bis hinter dem Boss ein Portal erscheint. Nehmt das auf der Karte als Ausgang mit der Bezeichnung ^The Last Prison^ markierte Portal.",
    ["After killing ^Zek'voz^, go back the way you came to arrive back in the ^Ring of Containment^."] = "Nachdem Ihr ^Zek'voz^ getötet habt, kehrt auf demselben Weg zu ^Ring of Containment^ zurück.",
    ["After killing ^Zor'lok^, take the northwest stairwell and follow the path into the next room to find ^Blade Lord Ta'yak^. Kill trash in all 4 corners to begin the fight."] = "Nachdem Ihr ^Zor'lok^ getötet habt, nehmt das nordwestliche Treppenhaus und folgt dem Weg in den nächsten Raum zu ^Blade Lord Ta'yak^. Tötet die Gegner in allen 4 Ecken, um den Kampf zu beginnen.",
    ["After killing ^Zul^, activate the ^Titan Console^ on the south end of the platform. Then jump into ^The Festering Core^ to fight ^Mythrax the Unraveler^."] = "Nachdem Ihr ^Zul^ getötet habt, aktiviert die ^Titan Console^ am südlichen Ende der Plattform. Springt anschließend in ^The Festering Core^, um gegen ^Mythrax the Unraveler^ zu kämpfen.",
    ["After killing both ^Skolex^ and ^Artificer Xy'mox^, follow the path south to ^Halondrus^."] = "Nachdem Ihr sowohl ^Skolex^ als auch ^Artificer Xy'mox^ getötet habt, folgt dem Weg nach Süden zu ^Halondrus^.",
    ["After killing the ^Twin Empyreans^, take the southeastern exit from the room."] = "Nachdem Ihr ^Twin Empyreans^ getötet habt, nehmt den südöstlichen Ausgang aus dem Raum.",
    ["After landing below, follow the path to reach ^Scalecommander Sarkareth^."] = "Folgt nach der Landung unten dem Weg zu ^Scalecommander Sarkareth^.",
    ["After landing down below, take the downhill path and kill trash as you walk through the ^Helheim^ portal at the bottom."] = "Nehmt nach der Landung unten den abwärtsführenden Weg und tötet unterwegs die Gegner, während Ihr unten durch das Portal nach ^Helheim^ geht.",
    ["After landing from ^Gust of Wind^, follow the path back out to ^The Primal Convergence^."] = "Folgt nach der Landung durch ^Gust of Wind^ dem Weg zurück zu ^The Primal Convergence^.",
    ["After landing in ^Domination's Grasp^, proceed up the ramp. After some dialog, you can engage ^Anduin Wrynn^."] = "Geht nach der Landung in ^Domination's Grasp^ die Rampe hinauf. Nach einem Dialog könnt Ihr ^Anduin Wrynn^ angreifen.",
    ["After landing in ^Rift of Aln^, start killing trash. They will continue coming in waves until finally, you will meet ^Xavius^."] = "Beginnt nach der Landung in ^Rift of Aln^ damit, Gegner zu töten. Sie erscheinen in mehreren Wellen, bis Ihr schließlich auf ^Xavius^ trefft.",
    ["After landing in ^The Exhaust^, move forward to start the encounter with ^Imonar the Soulhunter^."] = "Geht nach der Landung in ^The Exhaust^ vorwärts, um die Begegnung mit ^Imonar the Soulhunter^ zu beginnen.",
    ["After landing in ^The Traverse^, make your way to the bottom of the room by walking over a sequence of teleporting panels on the floor."] = "Begebt euch nach der Landung in ^The Traverse^ zum unteren Ende des Raums, indem Ihr über eine Reihe teleportierender Bodenplatten lauft.",
    ["After landing in the ^Genesis Cradle^, follow the path to ^Dausegne^."] = "Folgt nach der Landung in ^Genesis Cradle^ dem Weg zu ^Dausegne^.",
    ["After landing in the next area, go west to reach ^Shadow-Lord Iskar^."] = "Geht nach der Landung im nächsten Bereich nach Westen zu ^Shadow-Lord Iskar^.",
    ["After landing on the ship, make your way to the top of the ship and talk to ^Tandred Proudmoore^ to proceed."] = "Begebt euch nach der Landung auf dem Schiff auf dessen Oberdeck und sprecht mit ^Tandred Proudmoore^, um fortzufahren.",
    ["After landing up top, follow the path around to the map exit labeled ^The Hive^."] = "Folgt nach der Landung oben dem Weg zum Kartenausgang mit der Bezeichnung ^The Hive^.",
    ["After landing, clear trash in the water, then move up the short ramp and clear the remaining trash to engage ^Iron Maidens^."] = "Beseitigt nach der Landung die Gegner im Wasser, geht die kurze Rampe hinauf und beseitigt die übrigen Gegner, um ^Iron Maidens^ anzugreifen.",
    ["After landing, continue ahead to find ^Durumu the Forgotten^. Clear all trash in the room to spawn the boss."] = "Geht nach der Landung weiter zu ^Durumu the Forgotten^. Beseitigt alle Gegner im Raum, damit der Boss erscheint.",
    ["After landing, follow the path ahead to reach ^Sinestra^."] = "Folgt nach der Landung dem Weg vor euch zu ^Sinestra^.",
    ["After landing, follow the path down to the map exit labeled ^Maw of Gor'ma^."] = "Folgt nach der Landung dem Weg hinunter zum Kartenausgang mit der Bezeichnung ^Maw of Gor'ma^.",
    ["After landing, follow the path to kill |cffF259C7(1)|r ^Volcanius^, then |cffF259C7(2)|r ^Eranog^."] = "Folgt nach der Landung dem Weg und tötet |cffF259C7(1)|r ^Volcanius^, dann |cffF259C7(2)|r ^Eranog^.",
    ["After landing, follow the path to the final map exit labeled ^N'Zoth^. Kill adds on the bridge to spawn a portal at the end."] = "Folgt nach der Landung dem Weg zum letzten Kartenausgang mit der Bezeichnung ^N'Zoth^. Tötet die Gegner auf der Brücke, damit am Ende ein Portal erscheint.",
    ["After landing, kill ^Warlord Zon'ozz^ right in front of you."] = "Tötet nach der Landung direkt vor euch ^Warlord Zon'ozz^.",
    ["After landing, kill ^Yor'sahj^ in the middle of the room."] = "Tötet nach der Landung ^Yor'sahj^ in der Mitte des Raums.",
    ["After landing, move forward and click the ^Lightforged Beacon^ to be teleported to ^The Exhaust^."] = "Geht nach der Landung vorwärts und klickt auf das ^Lightforged Beacon^, um nach ^The Exhaust^ teleportiert zu werden.",
    ["After landing, proceed down the steps to clear trash and begin the fight with ^High Tinker Mekkatorque^."] = "Geht nach der Landung die Stufen hinunter, beseitigt die Gegner und beginnt den Kampf gegen ^High Tinker Mekkatorque^.",
    ["After opening the door, proceed ahead to witness a lengthy dialog before engaging ^Garrosh Hellscream^."] = "Geht nach dem Öffnen der Tür weiter, wartet einen längeren Dialog ab und greift anschließend ^Garrosh Hellscream^ an.",
    ["After reaching the bottom of the elevator, take a right and follow the path to reach ^Maloriak^."] = "Biegt am unteren Ende des Aufzugs rechts ab und folgt dem Weg zu ^Maloriak^.",
    ["After reaching the bottom of the stairs, proceed forward to trigger a lengthy dialog, then engage ^Ra-den^."] = "Geht am unteren Ende der Treppe vorwärts, wartet den längeren Dialog ab und greift dann ^Ra-den^ an.",
    ["After reaching the top of the elevator, follow the path back to find ^Ra-den the Despoiled^."] = "Folgt oben am Aufzug dem Weg zurück zu ^Ra-den the Despoiled^.",
    ["After reaching the top of the elevator, make your way down the path and clear the trash to engage ^Vexiona^."] = "Folgt oben am Aufzug dem Weg hinunter und beseitigt die Gegner, um ^Vexiona^ anzugreifen.",
    ["After reaching the top of the stairs and opening a door, you will encounter ^The Coven of Shivarra^."] = "Nachdem Ihr das obere Ende der Treppe erreicht und eine Tür geöffnet habt, trefft Ihr auf ^The Coven of Shivarra^.",
    ["After respawning in ^Chamber of the Moon^, proceed towards the group of NPCs and enter the descending stairwell behind them."] = "Geht nach dem Wiedererscheinen in ^Chamber of the Moon^ zur NPC-Gruppe und nehmt das abwärtsführende Treppenhaus hinter ihnen.",
    ["After returning to ^Wyrmrest Temple^, click ^Nethestrasz^, the dragon in front of you. Once you reach the top, click the portal to ^Travel to the Eye of Eternity^."] = "Klickt nach der Rückkehr zum ^Wyrmrest Temple^ auf ^Nethestrasz^, den Drachen vor euch. Klickt oben auf das Portal nach ^Travel to the Eye of Eternity^.",
    ["After returning to ^Wyrmrest Temple^, click ^Nethestrasz^, the dragon in front of you. Once you reach the top, wait on a lengthy dialog and click the portal to ^Travel to the Eye of Eternity^."] = "Klickt nach der Rückkehr zum ^Wyrmrest Temple^ auf ^Nethestrasz^, den Drachen vor euch. Wartet oben den längeren Dialog ab und klickt dann auf das Portal nach ^Travel to the Eye of Eternity^.",
    ["After returning to ^Wyrmrest Temple^, click on ^Eiendormi^, the dragon on the right."] = "Klickt nach der Rückkehr zum ^Wyrmrest Temple^ auf ^Eiendormi^, den Drachen auf der rechten Seite.",
    ["After returning to the ^Halls of the Chosen^, follow the path all the way north to kill ^Radiance of Azshara^. Clear all the trash to start the encounter."] = "Folgt nach der Rückkehr zu ^Halls of the Chosen^ dem Weg ganz nach Norden und tötet ^Radiance of Azshara^. Beseitigt alle Gegner, um die Begegnung zu beginnen.",
    ["After returning to the ^Halls of the Chosen^, walk straight ahead to kill a couple ^Azsh'ari Channelers^ and click the ^Font of Power^."] = "Geht nach der Rückkehr zu ^Halls of the Chosen^ geradeaus, tötet einige ^Azsh'ari Channelers^ und klickt auf ^Font of Power^.",
    ["After returning to the central hub, approach the middle of the room and interact with the ^Nightmare Iris^ to reach ^Moonglade^."] = "Geht nach der Rückkehr zum zentralen Bereich in die Mitte des Raums und interagiert mit dem ^Nightmare Iris^, um ^Moonglade^ zu erreichen.",
    ["After returning to the central hub, continue clockwise through the next portal to reach ^Mulgore^."] = "Geht nach der Rückkehr zum zentralen Bereich im Uhrzeigersinn weiter durch das nächste Portal nach ^Mulgore^.",
    ["After returning to the central hub, talk to ^Malfurion^ then interact with the ^Nightmare Iris^ to continue."] = "Sprecht nach der Rückkehr zum zentralen Bereich mit ^Malfurion^ und interagiert dann mit dem ^Nightmare Iris^, um fortzufahren.",
    ["After returning to the main courtyard, follow the path all the way to the far southeast of the map to reach ^Krosus^."] = "Folgt nach der Rückkehr zum Haupthof dem Weg bis ganz in den Südosten der Karte zu ^Krosus^.",
    ["After some dialog, kill the trash wave that spawns, and ^Kargath Bladefist^ will enter the ring."] = "Tötet nach dem Dialog die erscheinende Gegnerwelle, woraufhin ^Kargath Bladefist^ den Ring betritt.",
    ["After spawning, cross the chasm using the ^Lightforged Teleport Pod^. Stay to the left when you reach the intersection, and follow the path to interact with a ^Portal^."] = "Überquert nach dem Erscheinen die Schlucht mit dem ^Lightforged Teleport Pod^. Haltet euch an der Kreuzung links und folgt dem Weg zu einem ^Portal^.",
    ["After surfacing from the water, follow the path around to reach ^The Queen's Court^."] = "Folgt nach dem Auftauchen aus dem Wasser dem Weg zu ^The Queen's Court^.",
    ["After switching to Alliance, follow the path up the stairs and around to the map exit labeled ^Halls of Opulence^. Jump in the hole at the end of the path."] = "Folgt nach dem Wechsel zur Allianz dem Weg die Treppe hinauf zum Kartenausgang mit der Bezeichnung ^Halls of Opulence^. Springt am Ende des Weges in das Loch.",
    ["After taking the portal into ^The Last Prison^, you will watch some lengthy dialog then click the ^Titan Console^ in front of you to engage ^Queen Azshara^."] = "Nachdem Ihr das Portal nach ^The Last Prison^ genommen habt, wartet den längeren Dialog ab und klickt dann vor euch auf die ^Titan Console^, um ^Queen Azshara^ anzugreifen.",
    ["After taking the portal, follow the long, linear path towards the next map exit labeled ^Elarian Sanctuary^."] = "Folgt nach dem Portal dem langen, geradlinigen Weg zum nächsten Kartenausgang mit der Bezeichnung ^Elarian Sanctuary^.",
    ["After taking the portal, follow the path around to find ^Twin Ogron^. Clear trash to start the encounter."] = "Folgt nach dem Portal dem Weg zu ^Twin Ogron^. Beseitigt die Gegner, um die Begegnung zu beginnen.",
    ["After taking the portal, follow the path around to reach ^Kel'Thuzad^."] = "Folgt nach dem Portal dem Weg zu ^Kel'Thuzad^.",
    ["After taking the portal, move ahead to clear trash to open the door and reach the final boss, ^Imperator Mar'gok^."] = "Geht nach dem Portal weiter, beseitigt die Gegner, um die Tür zu öffnen, und erreicht den letzten Boss, ^Imperator Mar'gok^.",
    ["After taking the portal, you will arrive in ^Destructor's Rise^. On ^Mythic^, do NOT kill the ^Fel Iron Summoners^. Just tag them, and let ^Mannoroth^ kill them or you could bug the encounter. On other difficulties, kill the ^Fel Iron Summoners^ to begin the fight."] = "Nach dem Portal gelangt Ihr nach ^Destructor's Rise^. Tötet auf ^Mythic^ NICHT die ^Fel Iron Summoners^. Greift sie nur kurz an und lasst sie von ^Mannoroth^ töten, da die Begegnung sonst fehlerhaft werden kann. Tötet auf anderen Schwierigkeitsgraden die ^Fel Iron Summoners^, um den Kampf zu beginnen.",
    ["After taking the teleport, follow the path to reach ^Portal Keeper Hasabel^."] = "Folgt nach der Teleportation dem Weg zu ^Portal Keeper Hasabel^.",
    ["After taking the teleport, make your way for the right-most exit labeled ^Verdant Terrace^."] = "Nehmt nach der Teleportation den äußersten rechten Ausgang mit der Bezeichnung ^Verdant Terrace^.",
    ["After taking the teleport, you will land right in front of ^Archimonde^. Kill him!"] = "Nach der Teleportation landet Ihr direkt vor ^Archimonde^. Tötet ihn!",
    ["After taking the teleporter to ^Nightcloak Sanctum^, follow the path around to the ^Stone Legion Generals^. Clear trash to start the encounter."] = "Folgt nach der Teleportation nach ^Nightcloak Sanctum^ dem Weg zu ^Stone Legion Generals^. Beseitigt die Gegner, um die Begegnung zu beginnen.",
    ["After teleporting back to ^The Grand Walk^, follow the path up to where you killed ^Shriekwing^ (again). After some dialog, ^Sludgefist^ will jump down to fight."] = "Folgt nach der Teleportation zurück nach ^The Grand Walk^ dem Weg hinauf zu der Stelle, an der Ihr ^Shriekwing^ getötet habt. Nach einem Dialog springt ^Sludgefist^ herunter und greift an.",
    ["After teleporting, follow the path to ^Eye of the Jailer^ and clear all trash on his platform. To reach the far side, walk to the pile of chains and use the extra action button"] = "Folgt nach der Teleportation dem Weg zu ^Eye of the Jailer^ und beseitigt alle Gegner auf seiner Plattform. Geht zum Kettenhaufen und benutzt die Extraaktionsschaltfläche, um die andere Seite zu erreichen",
    ["After teleporting, proceed ahead to witness a lengthy dialog before engaging ^Garrosh Hellscream^."] = "Geht nach der Teleportation weiter, wartet den längeren Dialog ab und greift anschließend ^Garrosh Hellscream^ an.",
    ["After teleporting, proceed forward and click on one of the ^Lightforged Warframes^ to be flown to the next area."] = "Geht nach der Teleportation vorwärts und klickt auf einen der ^Lightforged Warframes^, um in den nächsten Bereich geflogen zu werden.",
    ["After teleporting, take the spiral stairwell down in the middle of the room."] = "Nehmt nach der Teleportation die Wendeltreppe in der Mitte des Raums nach unten.",
    ["After the first trash pack of scorpions, there will be a door opened to the right at the end of the hallway. Inside the room, you will find a teleporter that will allow you to teleport to:\n  - Palace Entrance (^Spellblade Aluriel^)\n  - Palace Courtyard (^Krosus^)\n  - Nightspire (^Elisande^)\n\nNote: RetroRuns only has the route built for Elisande at this time."] = "Nach der ersten Gruppe Skorpione öffnet sich am Ende des Gangs rechts eine Tür. Im Raum findet Ihr einen Teleporter, mit dem Ihr euch an folgende Orte teleportieren könnt:\n  - Palasteingang (^Spellblade Aluriel^)\n  - Palasthof (^Krosus^)\n  - Nachtspitze (^Elisande^)\n\nHinweis: RetroRuns enthält derzeit nur die Route für Elisande.",
    ["After the teleport, you should be standing across from ^Fyrakk^. Approach him to start the encounter."] = "Nach der Teleportation solltet Ihr gegenüber von ^Fyrakk^ stehen. Nähert euch ihm, um die Begegnung zu beginnen.",
    ["After walking through the door, follow the path to ^Paragons of the Klaxxi^. Clear trash and click ^Mantid Amber^ in the middle of the room to start the encounter."] = "Folgt nach der Tür dem Weg zu ^Paragons of the Klaxxi^. Beseitigt die Gegner und klickt in der Mitte des Raums auf ^Mantid Amber^, um die Begegnung zu beginnen.",
    ["After walking through the portal into ^Grizzly Hills^, follow the path around to find ^Ursoc^."] = "Folgt nach dem Portal nach ^Grizzly Hills^ dem Weg zu ^Ursoc^.",
    ["After walking through the portal, continue on the path and walk through the second portal to ^The Emerald Nightmare^."] = "Folgt nach dem Portal dem Weg weiter und geht durch das zweite Portal nach ^The Emerald Nightmare^.",
    ["After you land, enter the room and clear the trash to spawn ^Echo of Neltharion^."] = "Betretet nach der Landung den Raum und beseitigt die Gegner, damit ^Echo of Neltharion^ erscheint.",
    ["After you reach the next area, go downstairs and kill trash to begin the fight against ^High Tinker Mekkatorque^."] = "Geht im nächsten Bereich die Treppe hinunter und tötet die Gegner, um den Kampf gegen ^High Tinker Mekkatorque^ zu beginnen.",
    ["After zoning in, click ^Blackrock Artifact^ on either side of the bridge, and it will open the gate leading across the bridge. Go forward and follow the route across the bridge."] = "Klickt nach dem Betreten der Instanz auf einer der beiden Seiten der Brücke auf ^Blackrock Artifact^, damit sich das Tor zur Brücke öffnet. Geht vorwärts und folgt der Route über die Brücke.",
    ["After zoning in, click the ^Scroll of Past Deeds^ on the wall to skip ahead to ^Garrosh^. It's on the wall next to ^Lorewalker Cho^."] = "Klickt nach dem Betreten der Instanz auf die ^Scroll of Past Deeds^ an der Wand, um direkt zu ^Garrosh^ zu gelangen. Sie befindet sich an der Wand neben ^Lorewalker Cho^.",
    ["After zoning in, click the portal on the right for ^Destructor's Rise^ to be teleported to ^Mannoroth^."] = "Klickt nach dem Betreten der Instanz auf das rechte Portal nach ^Destructor's Rise^, um zu ^Mannoroth^ teleportiert zu werden.",
    ["After zoning in, click the portal to ^Wyrmrest Summit^ right in front of you."] = "Klickt nach dem Betreten der Instanz direkt vor euch auf das Portal nach ^Wyrmrest Summit^.",
    ["After zoning in, continue ahead to find ^Durumu the Forgotten^. Clear all trash in the room to spawn the boss."] = "Geht nach dem Betreten der Instanz weiter zu ^Durumu the Forgotten^. Beseitigt alle Gegner im Raum, damit der Boss erscheint.",
    ["After zoning in, continue following the linear path to reach the map exit labeled ^The Nighthold^."] = "Folgt nach dem Betreten der Instanz dem geradlinigen Weg zum Kartenausgang mit der Bezeichnung ^The Nighthold^.",
    ["After zoning in, continue up the stairwell towards the map exit labeled ^Halls of Opulence^. Jump in the hole when you reach the end of the path."] = "Geht nach dem Betreten der Instanz das Treppenhaus hinauf zum Kartenausgang mit der Bezeichnung ^Halls of Opulence^. Springt am Ende des Weges in das Loch.",
    ["After zoning in, enter the room on the left and enter the portal at the map exit labeled ^Elunaria^."] = "Betretet nach dem Betreten der Instanz den Raum auf der linken Seite und nehmt das Portal am Kartenausgang mit der Bezeichnung ^Elunaria^.",
    ["After zoning in, follow the linear path to ^Halfus Wyrmbreaker^."] = "Folgt nach dem Betreten der Instanz dem geradlinigen Weg zu ^Halfus Wyrmbreaker^.",
    ["After zoning in, follow the linear path to ^Lorewalker Cho^. Speak to him to trigger a series of trash encounters."] = "Folgt nach dem Betreten der Instanz dem geradlinigen Weg zu ^Lorewalker Cho^. Sprecht mit ihm, um eine Reihe von Kämpfen gegen Gegner zu starten.",
    ["After zoning in, follow the linear path to find the first boss, ^Garothi Worldbreaker^."] = "Folgt nach dem Betreten der Instanz dem geradlinigen Weg zum ersten Boss, ^Garothi Worldbreaker^.",
    ["After zoning in, follow the linear path to reach ^Imperial Vizier Zor'lok^. Clear all trash in his room to start the fight."] = "Folgt nach dem Betreten der Instanz dem geradlinigen Weg zu ^Imperial Vizier Zor'lok^. Beseitigt alle Gegner in seinem Raum, um den Kampf zu beginnen.",
    ["After zoning in, follow the main path to ^Vigilant Guardian^."] = "Folgt nach dem Betreten der Instanz dem Hauptweg zu ^Vigilant Guardian^.",
    ["After zoning in, follow the path ahead to reach ^Za'qul^."] = "Folgt nach dem Betreten der Instanz dem Weg vor euch zu ^Za'qul^.",
    ["After zoning in, follow the path around a few turns and up some stairs, killing trash on your way to ^Malkorok^."] = "Folgt nach dem Betreten der Instanz dem Weg über mehrere Kurven und Treppen und tötet unterwegs die Gegner bis zu ^Malkorok^.",
    ["After zoning in, follow the path around to ^Hellfire High Council^."] = "Folgt nach dem Betreten der Instanz dem Weg zu ^Hellfire High Council^.",
    ["After zoning in, follow the path around to find ^Ursoc^."] = "Folgt nach dem Betreten der Instanz dem Weg zu ^Ursoc^.",
    ["After zoning in, follow the path straight ahead to engage ^Sivara^."] = "Folgt nach dem Betreten der Instanz dem Weg geradeaus und greift ^Sivara^ an.",
    ["After zoning in, follow the path straight ahead to find and kill ^The Restless Cabal^."] = "Folgt nach dem Betreten der Instanz dem Weg geradeaus zu ^The Restless Cabal^ und tötet sie.",
    ["After zoning in, follow the path to ^Gnarlroot^. Clear the trash around him to start the encounter."] = "Folgt nach dem Betreten der Instanz dem Weg zu ^Gnarlroot^. Beseitigt die Gegner um ihn herum, um die Begegnung zu beginnen.",
    ["After zoning in, follow the path to ^Maw of Gor'ma^."] = "Folgt nach dem Betreten der Instanz dem Weg zu ^Maw of Gor'ma^.",
    ["After zoning in, follow the path to the right and make your way down a spiral ramp."] = "Folgt nach dem Betreten der Instanz dem Weg nach rechts und die spiralförmige Rampe hinab.",
    ["After zoning in, follow the path to the right, and make your way towards the map exit labeled ^Defiant Ramparts^."] = "Folgt nach dem Betreten der Instanz dem Weg nach rechts zum Kartenausgang mit der Bezeichnung ^Defiant Ramparts^.",
    ["After zoning in, go downstairs and kill trash to begin the fight against ^High Tinker Mekkatorque^."] = "Geht nach dem Betreten der Instanz die Treppe hinunter und tötet die Gegner, um den Kampf gegen ^High Tinker Mekkatorque^ zu beginnen.",
    ["After zoning in, go left to find ^Fel Lord Zakuun^."] = "Geht nach dem Betreten der Instanz nach links zu ^Fel Lord Zakuun^.",
    ["After zoning in, go straight ahead and clear all trash to spawn ^Kazzara^."] = "Geht nach dem Betreten der Instanz geradeaus und beseitigt alle Gegner, damit ^Kazzara^ erscheint.",
    ["After zoning in, go straight ahead to engage ^Sire Denathrius^."] = "Geht nach dem Betreten der Instanz geradeaus und greift ^Sire Denathrius^ an.",
    ["After zoning in, go to the West platform to start the fight with ^Conclave of the Wind^."] = "Begebt euch nach dem Betreten der Instanz auf die westliche Plattform, um den Kampf gegen ^Conclave of the Wind^ zu beginnen.",
    ["After zoning in, go up the stairs to the right to reach the ^Omnotron Defense System^."] = "Geht nach dem Betreten der Instanz die Treppe rechts hinauf zu ^Omnotron Defense System^.",
    ["After zoning in, go west to reach ^Shadow-Lord Iskar^."] = "Geht nach dem Betreten der Instanz nach Westen zu ^Shadow-Lord Iskar^.",
    ["After zoning in, head down the stairs and move straight ahead to engage ^Immerseus^."] = "Geht nach dem Betreten der Instanz die Treppe hinunter und geradeaus, um ^Immerseus^ anzugreifen.",
    ["After zoning in, head for the map exit labeled ^The Scorched Hall^."] = "Begebt euch nach dem Betreten der Instanz zum Kartenausgang mit der Bezeichnung ^The Scorched Hall^.",
    ["After zoning in, head for the map exit labeled ^Verdant Terrace^."] = "Begebt euch nach dem Betreten der Instanz zum Kartenausgang mit der Bezeichnung ^Verdant Terrace^.",
    ["After zoning in, head straight ahead and follow the route across the bridge."] = "Geht nach dem Betreten der Instanz geradeaus und folgt der Route über die Brücke.",
    ["After zoning in, head through the door and proceed to the exit marked on the map."] = "Geht nach dem Betreten der Instanz durch die Tür zum auf der Karte markierten Ausgang.",
    ["After zoning in, head to the right wing to engage ^Argaloth^."] = "Begebt euch nach dem Betreten der Instanz in den rechten Flügel und greift ^Argaloth^ an.",
    ["After zoning in, interact with the dragon to be flown to ^Tindral Sageswift, Seer of the Flame^."] = "Interagiert nach dem Betreten der Instanz mit dem Drachen, um zu ^Tindral Sageswift, Seer of the Flame^ geflogen zu werden.",
    ["After zoning in, jump in the purple portal in front of you."] = "Springt nach dem Betreten der Instanz in das violette Portal vor euch.",
    ["After zoning in, jump into ^The Festering Core^ to fight ^Mythrax the Unraveler^."] = "Springt nach dem Betreten der Instanz in ^The Festering Core^, um gegen ^Mythrax the Unraveler^ zu kämpfen.",
    ["After zoning in, make your way down the long path to find ^Kin'garoth^."] = "Folgt nach dem Betreten der Instanz dem langen Weg zu ^Kin'garoth^.",
    ["After zoning in, make your way down the path in front of you. When you can, hang a left and work your way around to ^Beth'tilac^."] = "Folgt nach dem Betreten der Instanz dem Weg vor euch. Haltet euch bei der ersten Gelegenheit links und folgt dem Weg zu ^Beth'tilac^.",
    ["After zoning in, make your way to the other end of the room. Open the door to find ^Jin'rokh the Breaker^."] = "Geht nach dem Betreten der Instanz zum anderen Ende des Raums. Öffnet die Tür zu ^Jin'rokh the Breaker^.",
    ["After zoning in, make your way up the path and stay to the right and find the map exit labeled ^The Ritual Chamber^."] = "Folgt nach dem Betreten der Instanz dem Weg hinauf, haltet euch rechts und sucht den Kartenausgang mit der Bezeichnung ^The Ritual Chamber^.",
    ["After zoning in, move ahead and follow the north path out of ^Shriekwing^'s room and go down the stairs. Kill the trash, and ^General Draven^ will come open the gate. Kill a few trash mobs then engage ^Huntsman Altimor^."] = "Geht nach dem Betreten der Instanz vorwärts, folgt dem nördlichen Weg aus dem Raum von ^Shriekwing^ und geht die Treppe hinunter. Tötet die Gegner, damit ^General Draven^ das Tor öffnet. Tötet einige weitere Gegner und greift dann ^Huntsman Altimor^ an.",
    ["After zoning in, move ahead and kill the trash to begin the encounter with ^Protectors of the Endless^."] = "Geht nach dem Betreten der Instanz vorwärts und tötet die Gegner, um die Begegnung mit ^Protectors of the Endless^ zu beginnen.",
    ["After zoning in, move ahead to clear trash to open the door and reach the final boss, ^Imperator Mar'gok^."] = "Geht nach dem Betreten der Instanz weiter, beseitigt die Gegner, um die Tür zu öffnen, und erreicht den letzten Boss, ^Imperator Mar'gok^.",
    ["After zoning in, move ahead to find ^The Stone Guard^."] = "Geht nach dem Betreten der Instanz weiter zu ^The Stone Guard^.",
    ["After zoning in, move forward and take your first left to reach ^Skorpyron^."] = "Geht nach dem Betreten der Instanz vorwärts und biegt an der ersten Möglichkeit links zu ^Skorpyron^ ab.",
    ["After zoning in, move up the stairwell and follow the path to open a masked gate."] = "Geht nach dem Betreten der Instanz das Treppenhaus hinauf und folgt dem Weg, um ein versiegeltes Tor zu öffnen.",
    ["After zoning in, proceed across the bridge. On the beach, your goal is to destroy (7) ^Kor'kron Cannons^. Click the ^Spike Mines^ next to each cannon to destroy them."] = "Überquert nach dem Betreten der Instanz die Brücke. Zerstört am Strand (7) ^Kor'kron Cannons^. Klickt neben jeder Kanone auf die ^Spike Mines^, um sie zu zerstören.",
    ["After zoning in, proceed ahead into ^Shriekwing^'s room and take the southern map exit labeled ^Halls of the Faithful^."] = "Geht nach dem Betreten der Instanz in den Raum von ^Shriekwing^ und nehmt den südlichen Kartenausgang mit der Bezeichnung ^Halls of the Faithful^.",
    ["After zoning in, proceed ahead to ^Maiden of Vigilance^."] = "Geht nach dem Betreten der Instanz weiter zu ^Maiden of Vigilance^.",
    ["After zoning in, proceed ahead to engage ^Aggramar^."] = "Geht nach dem Betreten der Instanz weiter und greift ^Aggramar^ an.",
    ["After zoning in, proceed ahead to the ^Captain's Quarters^ entrance on the map. Inside the ^Captain's Quarters^, take your first right to go up a short stairwell."] = "Geht nach dem Betreten der Instanz zum auf der Karte markierten Eingang ^Captain's Quarters^. Biegt in ^Captain's Quarters^ bei der ersten Gelegenheit rechts ab und geht die kurze Treppe hinauf.",
    ["After zoning in, proceed down the first hallway and clear the scorpion trash to open a door on your right. Click the ^Suramar Portal^ and teleport to the ^Nightspire^."] = "Geht nach dem Betreten der Instanz den ersten Gang entlang und beseitigt die Skorpiongegner, damit sich rechts eine Tür öffnet. Klickt auf das ^Suramar Portal^ und teleportiert euch nach ^Nightspire^.",
    ["After zoning in, proceed forward and clear the slimes to begin the encounter with ^Nythendra^."] = "Geht nach dem Betreten der Instanz vorwärts und beseitigt die Schleime, um die Begegnung mit ^Nythendra^ zu beginnen.",
    ["After zoning in, proceed forward out of ^The Coliseum^."] = "Geht nach dem Betreten der Instanz vorwärts aus ^The Coliseum^ hinaus.",
    ["After zoning in, proceed straight ahead to ^Champion of the Light^."] = "Geht nach dem Betreten der Instanz geradeaus zu ^Champion of the Light^.",
    ["After zoning in, proceed straight ahead to ^Lady Ashvane^."] = "Geht nach dem Betreten der Instanz geradeaus zu ^Lady Ashvane^.",
    ["After zoning in, proceed straight ahead to engage ^Goroth^."] = "Geht nach dem Betreten der Instanz geradeaus und greift ^Goroth^ an.",
    ["After zoning in, proceed straight ahead to engage ^Magmorax^. Kill trash to start the encounter."] = "Geht nach dem Betreten der Instanz geradeaus und greift ^Magmorax^ an. Tötet die Gegner, um die Begegnung zu beginnen.",
    ["After zoning in, proceed straight ahead to engage ^Morchok^."] = "Geht nach dem Betreten der Instanz geradeaus und greift ^Morchok^ an.",
    ["After zoning in, proceed straight ahead to engage ^Tortos^."] = "Geht nach dem Betreten der Instanz geradeaus und greift ^Tortos^ an.",
    ["After zoning in, proceed straight ahead to the first boss room. Kill trash to start the encounter with ^Champion of the Light^."] = "Geht nach dem Betreten der Instanz geradeaus in den ersten Bossraum. Tötet die Gegner, um die Begegnung mit ^Champion of the Light^ zu beginnen.",
    ["After zoning in, read the ^Scroll of Past Deeds^ beside ^Lorewalker Cho^ to skip straight to ^Garrosh Hellscream^.\nThe scroll unlocks for your whole account once any character has defeated Garrosh."] = "Lest nach dem Betreten die ^Scroll of Past Deeds^ neben ^Lorewalker Cho^, um direkt zu ^Garrosh Hellscream^ zu gelangen.\nDie Schriftrolle wird für Euren gesamten Account freigeschaltet, sobald ein beliebiger Charakter Garrosh besiegt hat.",
    ["After zoning in, run up the stairs straight ahead to engage ^The Demonic Inquisition^."] = "Lauft nach dem Betreten der Instanz die Treppe geradeaus hinauf und greift ^The Demonic Inquisition^ an.",
    ["After zoning in, start killing trash. They will continue coming in waves until finally, you will meet ^Xavius^."] = "Beginnt nach dem Betreten der Instanz damit, Gegner zu töten. Sie erscheinen in mehreren Wellen, bis Ihr schließlich auf ^Xavius^ trefft.",
    ["After zoning in, take a left and head towards ^The Black Forge^. Take the elevator down."] = "Biegt nach dem Betreten der Instanz links ab und begebt euch zu ^The Black Forge^. Fahrt mit dem Aufzug nach unten.",
    ["After zoning in, take a right and head for the map exit labeled ^Gallery of Failures^."] = "Biegt nach dem Betreten der Instanz rechts ab und begebt euch zum Kartenausgang mit der Bezeichnung ^Gallery of Failures^.",
    ["After zoning in, take the escalator all the way up to engage ^Odyn^."] = "Nehmt nach dem Betreten der Instanz die Rolltreppe ganz nach oben und greift ^Odyn^ an.",
    ["After zoning in, take the middle path labeled ^The Clutchwarren^."] = "Nehmt nach dem Betreten der Instanz den mittleren Weg mit der Bezeichnung ^The Clutchwarren^.",
    ["After zoning in, take the northeastern path towards the ^Iron Assembly^."] = "Nehmt nach dem Betreten der Instanz den nordöstlichen Weg in Richtung ^Iron Assembly^.",
    ["After zoning in, talk to ^Gharg^ and tell him you're ready. He will send you up an elevator into ^The Coliseum^."] = "Sprecht nach dem Betreten der Instanz mit ^Gharg^ und sagt ihm, dass Ihr bereit seid. Er schickt euch mit einem Aufzug hinauf nach ^The Coliseum^.",
    ["After zoning in, talk to ^Wrathion^ to trigger a cutscene, then kill some adds to start the fight with ^Carapace of N'Zoth^."] = "Sprecht nach dem Betreten der Instanz mit ^Wrathion^, um eine Zwischensequenz auszulösen, und tötet dann einige Gegner, um den Kampf gegen ^Carapace of N'Zoth^ zu beginnen.",
    ["After zoning in, talk with ^Ensign Roberts^ to skip straight to ^Lady Jaina Proudmoore^."] = "Sprecht nach dem Betreten mit ^Ensign Roberts^, um direkt zu ^Lady Jaina Proudmoore^ zu gelangen.",
    ["After zoning in, talk with ^Otoye^ to skip straight to ^Lady Jaina Proudmoore^."] = "Sprecht nach dem Betreten mit ^Otoye^, um direkt zu ^Lady Jaina Proudmoore^ zu gelangen.",
    ["After zoning in, wait for the dialog to complete on the boat. You will be transported shortly."] = "Wartet nach dem Betreten der Instanz, bis der Dialog auf dem Boot beendet ist. Ihr werdet kurz darauf transportiert.",
    ["After zoning in, wait for the dialog to complete. You will be transported shortly."] = "Wartet nach dem Betreten der Instanz, bis der Dialog beendet ist. Ihr werdet kurz darauf transportiert.",
    ["After zoning in, walk straight ahead and kill the Tendrils to start the encounter with ^Taloc^."] = "Geht nach dem Betreten der Instanz geradeaus und tötet die Ranken, um die Begegnung mit ^Taloc^ zu beginnen.",
    ["After zoning in, walk up the ramp in front of you to find ^Wind Lord Mel'jarak^."] = "Geht nach dem Betreten der Instanz die Rampe vor euch hinauf zu ^Wind Lord Mel'jarak^.",
    ["After zoning in, you will find portals to your left/right depending on which skips you've unlocked.\n* Upper Citadel -> ^Shadow-Lord Iskar^\n* Destructor's Rise -> ^Mannoroth^\n\nNote: RetroRuns only has the route built for Mannoroth at this time."] = "Nach dem Betreten findet Ihr links oder rechts Portale, abhängig von euren freigeschalteten Abkürzungen.\n* Obere Zitadelle -> ^Shadow-Lord Iskar^\n* Aufstieg des Zerstörers -> ^Mannoroth^\n\nHinweis: RetroRuns enthält derzeit nur die Route für Mannoroth.",
    ["After zoning into ^Crown of Gorgoa^, follow the path North to ^Guardian of the First Ones^."] = "Folgt nach dem Betreten von ^Crown of Gorgoa^ dem Weg nach Norden zu ^Guardian of the First Ones^.",
    ["After zoning into ^Domination's Grasp^, proceed up the ramp. After some dialog, you can engage ^Anduin Wrynn^."] = "Geht nach dem Betreten von ^Domination's Grasp^ die Rampe hinauf. Nach einem Dialog könnt Ihr ^Anduin Wrynn^ angreifen.",
    ["After zoning into ^Genesis Cradle^, follow the path to ^Dausegne^."] = "Folgt nach dem Betreten von ^Genesis Cradle^ dem Weg zu ^Dausegne^.",
    ["After zoning into ^The Grand Design^, move straight ahead to ^The Jailer^'s platform and end this."] = "Geht nach dem Betreten von ^The Grand Design^ geradeaus zur Plattform von ^The Jailer^ und beendet es.",
    ["After zoning into ^The Primal Bulwark^, there are 3 paths available. Take the path on the right labeled ^The Vault Approach^."] = "Nach dem Betreten von ^The Primal Bulwark^ stehen 3 Wege zur Auswahl. Nehmt den rechten Weg mit der Bezeichnung ^The Vault Approach^.",
    ["After zoning into ^The Torment Chambers^, follow the path to ^Soulrender Dormazain^."] = "Folgt nach dem Betreten von ^The Torment Chambers^ dem Weg zu ^Soulrender Dormazain^.",
