    ["Click Teleportation Pad"] = "Teleportationsplattform anklicken",
    ["Click Teleporter"] = "Teleporter anklicken",
    ["Click the ^Downward Draft^ to be flown to the platform and engage ^Dathea, Ascended^."] = "Klickt auf den ^Downward Draft^, um zur Plattform geflogen zu werden, und greift ^Dathea, Ascended^ an.",
    ["Click the ^Hammer of Khaz'goroth^ in the middle of this room after killing ^Demonic Inquisition^."] = "Klickt in der Mitte dieses Raums auf den ^Hammer of Khaz'goroth^, nachdem Ihr ^Demonic Inquisition^ getötet habt.",
    ["Click the ^Tears of Elune^ in the middle of the room after killing ^The Desolate Host^."] = "Klickt in der Mitte des Raums auf die ^Tears of Elune^, nachdem Ihr ^The Desolate Host^ getötet habt.",
    ["Click the ^Tidestone of Golganneth^ after killing ^Mistress Sassz'ine^."] = "Klickt auf den ^Tidestone of Golganneth^, nachdem Ihr ^Mistress Sassz'ine^ getötet habt.",
    ["Click the portal to ^Wellspring Atrium^ to be teleported to the entrance."] = "Klickt auf das Portal zu ^Wellspring Atrium^, um zum Eingang teleportiert zu werden.",
    ["Click Tidestone"] = "Gezeitenstein anklicken",
    ["Click Titan Console"] = "Titanenkonsole anklicken",
    ["Click Titan Console then Jump In"] = "Titanenkonsole anklicken, hineinspringen",
    ["Click Valeera"] = "Valeera anklicken",
    ["Continue ahead into the main courtyard to find ^Spellblade Aluriel^."] = "Geht weiter in den Haupthof zu ^Spellblade Aluriel^.",
    ["Continue ahead to clear the trash and engage ^King Rastakhan^."] = "Geht weiter, beseitigt die Gegner und greift ^King Rastakhan^ an.",
    ["Continue backtracking through this room."] = "Geht weiter durch diesen Raum zurück.",
    ["Continue down spiral"] = "Spirale weiter hinab",
    ["Continue down the path and clear the trash to spawn ^The Amalgamation Chamber^."] = "Folgt dem Weg nach unten und beseitigt die Gegner, damit ^The Amalgamation Chamber^ erscheint.",
    ["Continue down the stairs, following the path until you reach ^Sisters of the Moon^."] = "Geht die Treppe weiter hinunter und folgt dem Weg bis zu ^Sisters of the Moon^.",
    ["Continue following the linear path into the next room."] = "Folgt dem geradlinigen Weg weiter in den nächsten Raum.",
    ["Continue following the path ahead to reach ^Sennarth^."] = "Folgt dem Weg vor euch weiter zu ^Sennarth^.",
    ["Continue following the path ahead to reach ^Terros^."] = "Folgt dem Weg vor euch weiter zu ^Terros^.",
    ["Continue following the path to arrive back at the ^The Primal Bulwark^."] = "Folgt dem Weg weiter zurück zu ^The Primal Bulwark^.",
    ["Continue following the path to engage ^Fetid Devourer^."] = "Folgt dem Weg weiter und greift ^Fetid Devourer^ an.",
    ["Continue following the path to reach ^Vectis^."] = "Folgt dem Weg weiter zu ^Vectis^.",
    ["Continue following the path to reach ^Zek'voz, Herald of N'Zoth^. Clear trash to start the encounter."] = "Folgt dem Weg weiter zu ^Zek'voz, Herald of N'Zoth^. Beseitigt die Gegner, um die Begegnung zu beginnen.",
    ["Continue forward to ^The Jailer^'s platform and end this."] = "Geht weiter zur Plattform von ^The Jailer^ und beendet es.",
    ["Continue straight ahead to engage ^Conclave of the Chosen^."] = "Geht geradeaus weiter und greift ^Conclave of the Chosen^ an.",
    ["Continue to Blackhand"] = "Weiter zu Blackhand",
    ["Continue up and around the stairwell until you reach ^Tichondrius^."] = "Geht das Treppenhaus weiter hinauf und herum, bis Ihr ^Tichondrius^ erreicht.",
    ["Continue working your way towards the central hub. When you get there, take the first path on the left and take the portal to ^Grizzly Hills^."] = "Arbeitet euch weiter zum zentralen Bereich vor. Nehmt dort den ersten Weg links und das Portal nach ^Grizzly Hills^.",
    ["Cross Bridge Ahead"] = "Brücke voraus überqueren",
    ["Cross Lava to Neltharion's Sanctum"] = "Lava zu Neltharions Heiligtum überqueren",
    ["Cross the bridge behind ^Anduin^ to the teleporter. Select ^Proceed^."] = "Überquert die Brücke hinter ^Anduin^ zum Teleporter. Wählt ^Proceed^.",
    ["Cross the room and take the southern exit."] = "Durchquert den Raum und nehmt den südlichen Ausgang.",
    ["Cross to Maiden"] = "Zu Maiden hinüber",
    ["Destroy Bells"] = "Glocken zerstören",
    ["Destroy Cannons"] = "Kanonen zerstören",
    ["Dialog then Anduin"] = "Dialog, dann Anduin",
    ["Dialog then Portal"] = "Dialog, dann Portal",
    ["Dialog then Raszageth"] = "Dialog, dann Raszageth",
    ["Dialog then Shriekwing"] = "Dialog, dann Shriekwing",
    ["Dialog then Sludgefist"] = "Dialog, dann Sludgefist",
    ["Dialog then Sylvanas"] = "Dialog, dann Sylvanas",
    ["Dialog then Titan Console"] = "Dialog, dann Titanenkonsole",
    ["Displacement Pad"] = "Versetzungsplattform",
    ["Door"] = "Tür",
    ["Down spiral to Shad'har"] = "Spirale hinab zu Shad'har",
    ["Down stairwell"] = "Treppenhaus hinab",
    ["Down to Cenarius"] = "Hinab zu Cenarius",
    ["Down to Cho"] = "Hinab zu Cho",
    ["Down to Sisters"] = "Hinab zu den Schwestern",
    ["Downstairs across to Magmaw"] = "Unten hinüber zu Magmaw",
    ["Dragons"] = "Drachen",
    ["Dragons then Khadgar"] = "Drachen, dann Khadgar",
    ["Draven Starts Sludgefist"] = "Draven startet Sludgefist",
    ["During dance phase, run to the spotlight. Walk in the direction of the other NPCs a few times. Jump to clear debuff stacks."] = "Lauft während der Tanzphase zum Scheinwerferlicht. Bewegt euch einige Male in dieselbe Richtung wie die anderen NPCs. Springt, um Stapel des Schwächungseffekts zu entfernen.",
    ["East Exit"] = "Ostausgang",
    ["East then Elevator"] = "Nach Osten, dann Aufzug",
    ["East then South"] = "Nach Osten, dann Süden",
    ["East to Elevator"] = "Nach Osten zum Aufzug",
    ["East to Xhul'horac"] = "Nach Osten zu Xhul'horac",
    ["Ebon Blade Acolyte"] = "Akolyth der Schwarzen Klinge",
    ["Eiendormi on Right"] = "Eiendormi rechts",
    ["Elevator"] = "Aufzug",
    ["Elevator to Blackhand"] = "Aufzug zu Blackhand",
    ["Elevator to Terrace"] = "Aufzug zur Terrasse",
    ["Elunaria Portal"] = "Portal nach Elunaria",
    ["Elysian Hold"] = "Archonhöhe",
    ["Emerald Nightmare Portal"] = "Portal zum Smaragdgrünen Alptraum",
    ["Ensign Roberts"] = "Ensign Roberts",
    ["Enter Cleft of Shadows"] = "Cleft of Shadows betreten",
    ["Enter Gates of Org"] = "Tore von Orgrimmar betreten",
    ["Enter Molten Crucible"] = "Molten Crucible betreten",
    ["Enter the next room and kill ^Drest'agath^."] = "Betretet den nächsten Raum und tötet ^Drest'agath^.",
    ["Enter the room to engage with ^The Hivemind^."] = "Betretet den Raum und greift ^The Hivemind^ an.",
    ["Enter the water and click the ^Oxygen-Rich Membrane^ for swim speed and water breathing. You must kill the last trash pack in the tunnel to spawn ^Blackwater Behemoth^."] = "Geht ins Wasser und klickt auf die ^Oxygen-Rich Membrane^, um schneller zu schwimmen und unter Wasser zu atmen. Ihr müsst die letzte Gegnergruppe im Tunnel töten, damit ^Blackwater Behemoth^ erscheint.",
    ["Essence of Eonar"] = "Essenz von Eonar",
    ["Exit portal nearby."] = "In der Nähe befindet sich ein Ausgangsportal.",
    ["Exit via Stairwell"] = "Über Treppenhaus hinaus",
    ["Fall then path to Uu'nat"] = "Hinabfallen, dann Weg zu Uu'nat",
    ["Find the teleporter behind ^Lihuvim^ and select ^Domination's Grasp^."] = "Sucht den Teleporter hinter ^Lihuvim^ und wählt ^Domination's Grasp^.",
    ["First left to Skorpyron"] = "Erste links zu Skorpyron",
    ["Fly Here"] = "Hierher fliegen",
    ["Fly into Sky Portal"] = "Ins Himmelsportal fliegen",
    ["Follow path"] = "Weg folgen",
    ["Follow Path Ahead"] = "Weg voraus folgen",
    ["Follow the foundry floor to ^Prototype Pantheon^."] = "Folgt dem Boden der Gießerei zu ^Prototype Pantheon^.",
    ["Follow the map from the entrance to ^the Tarragrue^."] = "Folgt der Karte vom Eingang zu ^the Tarragrue^.",
    ["Follow the mineshaft into the next room. After a lengthy dialog, speak to ^Norushen^ to start the encounter."] = "Folgt dem Minenschacht in den nächsten Raum. Sprecht nach einem längeren Dialog mit ^Norushen^, um die Begegnung zu beginnen.",
    ["Follow the path all the way back to find ^Il'gynoth, Corruption Reborn^."] = "Folgt dem Weg vollständig zurück zu ^Il'gynoth, Corruption Reborn^.",
    ["Follow the path all the way back to meet the ^Council of Dreams^. Click each of the illusions to start the fight."] = "Folgt dem Weg vollständig zurück zu ^Council of Dreams^. Klickt auf jede Illusion, um den Kampf zu beginnen.",
    ["Follow the path and kill ^Braekkas^ to open the wall. Continue on to find ^The Primal Council^."] = "Folgt dem Weg und tötet ^Braekkas^, um die Wand zu öffnen. Geht weiter zu ^The Primal Council^.",
    ["Follow the path around to ^Hellfire High Council^."] = "Folgt dem Weg zu ^Hellfire High Council^.",
    ["Follow the path back out to the main courtyard, and make your way to the ^Captain's Quarters^ entrance on the southwest corner of the map. Inside the ^Captain's Quarters^, take your first right to go up a short stairwell."] = "Folgt dem Weg zurück zum Haupthof und begebt euch zum Eingang ^Captain's Quarters^ in der südwestlichen Ecke der Karte. Biegt in ^Captain's Quarters^ bei der ersten Gelegenheit rechts ab und geht die kurze Treppe hinauf.",
    ["Follow the path down to ^Skolex^. Kill the trash to spawn the boss."] = "Folgt dem Weg hinunter zu ^Skolex^. Tötet die Gegner, damit der Boss erscheint.",
    ["Follow the path through ^The Endless Foundry^, killing the trash on the way to ^Lihuvim^."] = "Folgt dem Weg durch ^The Endless Foundry^ und tötet unterwegs die Gegner bis zu ^Lihuvim^.",
    ["Follow the path through ^The Grand Design^, killing trash on the way to ^Lords of Dread^."] = "Folgt dem Weg durch ^The Grand Design^ und tötet unterwegs die Gegner bis zu ^Lords of Dread^.",
    ["Follow the path to reach the ^Ascendant Council^."] = "Folgt dem Weg zu ^Ascendant Council^.",
    ["Follow the path to the boss area, and clear the trash to spawn ^Volcoross^."] = "Folgt dem Weg zum Bossbereich und beseitigt die Gegner, damit ^Volcoross^ erscheint.",
    ["Follow the path to the final map exit labeled ^N'Zoth^. Kill adds on the bridge to spawn a portal at the end."] = "Folgt dem Weg zum letzten Kartenausgang mit der Bezeichnung ^N'Zoth^. Tötet die Gegner auf der Brücke, damit am Ende ein Portal erscheint.",
    ["Follow the path to the map exit labeled ^The Hive^."] = "Folgt dem Weg zum Kartenausgang mit der Bezeichnung ^The Hive^.",
    ["Follow the path up and to the left to reach ^Tectus^. Kill the (3) rock golems to spawn the boss."] = "Folgt dem Weg hinauf und nach links zu ^Tectus^. Tötet die (3) Felsgolems, damit der Boss erscheint.",
    ["Follow the path up the stairs and around to the map exit labeled ^Halls of Opulence^. Jump in the hole at the end of the path."] = "Folgt dem Weg die Treppe hinauf zum Kartenausgang mit der Bezeichnung ^Halls of Opulence^. Springt am Ende des Weges in das Loch.",
    ["Follow the path up to ^Broodkeeper Diurna^."] = "Folgt dem Weg hinauf zu ^Broodkeeper Diurna^.",
    ["Follow the path. Once you reach the boss room, kill the final trash pack and talk to ^Lorewalker Cho^ to trigger the boss fight with ^Elegon^."] = "Folgt dem Weg. Tötet im Bossraum die letzte Gegnergruppe und sprecht mit ^Lorewalker Cho^, um den Bosskampf gegen ^Elegon^ auszulösen.",
    ["Font of Power"] = "Quell der Macht",
    ["For the knockback, position yourself between the boss and a tornado."] = "Positioniert euch für den Rückstoß zwischen dem Boss und einem Tornado.",
    ["Formation Seed"] = "Formationssamen",
    ["Forward to Imonar"] = "Vorwärts zu Imonar",
    ["From ^The Primal Convergence^, follow the path to the entrance labeled ^Iceskitter Hollow^."] = "Folgt von ^The Primal Convergence^ dem Weg zum Eingang mit der Bezeichnung ^Iceskitter Hollow^.",
    ["From ^Wellspring Atrium^, take the final remaining exit labeled ^Throne of the Firelord^. Click on the ^Formation Seed^ to construct a bridge to the next area."] = "Nehmt von ^Wellspring Atrium^ den letzten verbleibenden Ausgang mit der Bezeichnung ^Throne of the Firelord^. Klickt auf den ^Formation Seed^, um eine Brücke in den nächsten Bereich zu bauen.",
    ["From the top of the elevator, proceed ahead up the ramp to find the ^Antoran High Command^."] = "Geht oben am Aufzug die Rampe hinauf zu ^Antoran High Command^.",
    ["Fyrakk additionally drops {item}, an omnitoken that exchanges for any tier slot. Not tracked here."] = "Fyrakk lässt zusätzlich {item} fallen, einen universellen Token, der gegen einen beliebigen Setplatz eingetauscht werden kann. Wird hier nicht verfolgt.",
    ["Galewind Crag then Upward Draft"] = "Galewind Crag, dann Aufwind",
    ["Gauntlet then Dragons"] = "Spießrutenlauf, dann Drachen",
    ["General Draven"] = "General Draven",
    ["Go Here"] = "Hierher gehen",
    ["Grizzly Hills Portal"] = "Portal zu den Grizzlyhügeln",
    ["Hans & Franz"] = "Hans & Franz",
    ["Head down the long hallway to the teleporter. Select ^Ephemeral Plains Alpha^."] = "Folgt dem langen Gang zum Teleporter. Wählt ^Ephemeral Plains Alpha^.",
    ["Heal (or bandage) Kael. Kill Shade. Rinse/repeat as necessary."] = "Heilt Kael oder benutzt einen Verband. Tötet den Schatten. Wiederholt dies nach Bedarf.",
    ["Heart of the Forest"] = "Die Wurzeln",
    ["Hole Behind Neltharion"] = "Loch hinter Neltharion",
    ["Hole to East"] = "Loch im Osten",
    ["If you end up in the maze phase, collect a green orb and use it to bring down the barrier. Movement abilities can be used to get through the maze if needed."] = "Solltet Ihr in der Labyrinthphase landen, sammelt eine grüne Kugel und benutzt sie, um die Barriere zu senken. Bei Bedarf könnt Ihr Bewegungsfähigkeiten einsetzen, um durch das Labyrinth zu gelangen.",
    ["Imonar"] = "Imonar",
    ["In ^Halls of the Faithful^, wind your way around to the room overlooking the dancers. Clear the trash, and the NPCs will enter the room and open both gates. Follow the path opened by ^Prince Renathal^, and make your way up the stairs to ^Pride's Prison^."] = "Folgt in ^Halls of the Faithful^ dem gewundenen Weg zum Raum mit Blick auf die Tänzer. Beseitigt die Gegner, damit die NPCs den Raum betreten und beide Tore öffnen. Folgt dem von ^Prince Renathal^ geöffneten Weg und geht die Treppen hinauf zu ^Pride's Prison^.",
    ["In the ^Chamber of the Avatar^, move forward and kill trash to open the door, then watch some dialog before engaging with ^Fallen Avatar^."] = "Geht in ^Chamber of the Avatar^ vorwärts und tötet die Gegner, um die Tür zu öffnen. Wartet anschließend den Dialog ab und greift ^Fallen Avatar^ an.",
    ["In the boss room, kill all of the trash and approach the boss to start the encounter with ^Kormrok^."] = "Tötet im Bossraum alle Gegner und nähert euch dem Boss, um die Begegnung mit ^Kormrok^ zu beginnen.",
    ["In the next area, clear the trash before, on, and after the platform to force ^Gara'jal the Spiritbinder^ into combat."] = "Beseitigt im nächsten Bereich die Gegner vor, auf und hinter der Plattform, um ^Gara'jal the Spiritbinder^ zum Kampf zu zwingen.",
    ["In the next area, follow the path around a few turns and up some stairs, killing trash on your way to ^Malkorok^."] = "Folgt im nächsten Bereich dem Weg über mehrere Kurven und Treppen und tötet unterwegs die Gegner bis zu ^Malkorok^.",
    ["In the next area, follow the path to click a portal being channeled by ^Archmage Khadgar^."] = "Folgt im nächsten Bereich dem Weg zu einem von ^Archmage Khadgar^ kanalisierten Portal und klickt darauf.",
    ["In the next area, follow the path upstairs to the right and follow it around."] = "Geht im nächsten Bereich rechts die Treppe hinauf und folgt dem Weg.",
    ["In the next area, go east, then south down some stairs. When you reach the boss room, clear the trash to start the encounter with ^Socrethar the Eternal^."] = "Geht im nächsten Bereich nach Osten und dann einige Treppen nach Süden hinunter. Beseitigt im Bossraum die Gegner, um die Begegnung mit ^Socrethar the Eternal^ zu beginnen.",
    ["In the next area, kill several waves of trash. After killing ^Shanna Sparkfizz^, jump in the pipe to reach ^Siegecrafter Blackfuse^."] = "Tötet im nächsten Bereich mehrere Gegnerwellen. Springt nach dem Töten von ^Shanna Sparkfizz^ in das Rohr zu ^Siegecrafter Blackfuse^.",
    ["In the next area, move ahead into the cave to engage ^Tortos^."] = "Geht im nächsten Bereich vorwärts in die Höhle und greift ^Tortos^ an.",
    ["In the next area, talk to ^Wrathion^ to trigger a cutscene, then kill some adds to start the fight with ^Carapace of N'Zoth^."] = "Sprecht im nächsten Bereich mit ^Wrathion^, um eine Zwischensequenz auszulösen, und tötet dann einige Gegner, um den Kampf gegen ^Carapace of N'Zoth^ zu beginnen.",
    ["In the next area, you will pass through the spot where you killed ^Shadow-Lord Iskar^ previously. Continue following the path around, eventually reaching ^Fel Lord Zakuun^."] = "Ihr kommt im nächsten Bereich an der Stelle vorbei, an der Ihr zuvor ^Shadow-Lord Iskar^ getötet habt. Folgt dem Weg weiter bis zu ^Fel Lord Zakuun^.",
    ["Inside ^Defiant Ramparts^, follow the path to climb some stairs. Kill the last trash pack to spawn ^Assault of the Zaqali^."] = "Folgt in ^Defiant Ramparts^ dem Weg und geht die Treppen hinauf. Tötet die letzte Gegnergruppe, damit ^Assault of the Zaqali^ erscheint.",
    ["Inside ^Iron Assembly^, follow the path around to ^Beastlord Darmac^."] = "Folgt in ^Iron Assembly^ dem Weg zu ^Beastlord Darmac^.",
    ["Inside ^Orgrimmar^, move ahead into the boss tower to fight ^Kor'kron Dark Shaman^."] = "Geht in ^Orgrimmar^ vorwärts in den Bossturm und kämpft gegen ^Kor'kron Dark Shaman^.",
    ["Inside ^The Heart of the Empire^, follow the path around to find some NPCs mourning over the corpse of ^King Rastakhan^. Talk to ^Otoye^ to be switched to Alliance temporarily."] = "Folgt in ^The Heart of the Empire^ dem Weg zu einigen NPCs, die an der Leiche von ^King Rastakhan^ trauern. Sprecht mit ^Otoye^, um vorübergehend zur Allianz zu wechseln.",
    ["Inside ^The Nightspire^, clear trash around the room to begin the encounter with ^Grand Magistrix Elisande^."] = "Beseitigt in ^The Nightspire^ die Gegner im Raum, um die Begegnung mit ^Grand Magistrix Elisande^ zu beginnen.",
    ["Inside the ^Cleft of Shadows^, jump off to the left and head into another tunnel."] = "Springt in ^Cleft of Shadows^ links hinunter und geht in einen weiteren Tunnel.",
    ["Inside the ^Halls of Opulence^, proceed straight ahead to the middle area to engage ^Opulence^."] = "Geht in ^Halls of Opulence^ geradeaus zum mittleren Bereich und greift ^Opulence^ an.",
    ["Inside the ^Precipice of Dreams^, follow the path all the way west to kill ^Za'qul, Harbinger of Ny'alotha^."] = "Folgt in ^Precipice of Dreams^ dem Weg ganz nach Westen und tötet ^Za'qul, Harbinger of Ny'alotha^.",
    ["Inside the ^Roost of Ji-Kun^, make your way up and around the long series of paths and stairwells until you reach the platform of ^Ji-Kun^. Avoid the snails; they will still 1-shot you."] = "Folgt in ^Roost of Ji-Kun^ den langen Wegen und Treppen nach oben, bis Ihr die Plattform von ^Ji-Kun^ erreicht. Meidet die Schnecken, da sie euch weiterhin mit einem Treffer töten.",
    ["Inside the boss room, head straight ahead to engage ^Opulence^."] = "Geht im Bossraum geradeaus und greift ^Opulence^ an.",
    ["Inside the next tunnel, follow the long path to reach ^General Nazgrim^."] = "Folgt im nächsten Tunnel dem langen Weg zu ^General Nazgrim^.",
    ["Interrupt/kill both trees to start the fight. When she casts Weaver's Burden on you, run it away from your primary position to drop it out of the way. During intermission(s), interrupt/kill adds."] = "Unterbrecht oder tötet beide Bäume, um den Kampf zu beginnen. Wenn sie Webers Bürde auf euch wirkt, lauft von Eurer Hauptposition weg, damit der Effekt abseits abgelegt wird. Unterbrecht oder tötet während der Zwischenphasen die zusätzlichen Gegner.",
    ["Jaina then Portal"] = "Jaina, dann Portal",
    ["Jump between platforms, killing each of his limbs."] = "Springt zwischen den Plattformen und tötet jedes seiner Gliedmaßen.",
    ["Jump down"] = "Hinunterspringen",
    ["Jump from West -> North -> East and kill them all within 60 seconds of eachother."] = "Springt von Westen nach Norden und dann nach Osten und tötet sie alle innerhalb von 60 Sekunden.",
